import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import { Modal } from '../ui/Modal';
import { Button } from '../ui/Button';
import { toast } from '../ui/Toast';
import { FileDown, RefreshCw, CheckCircle2, AlertTriangle, AlertCircle, X, Edit2 } from 'lucide-react';
import { parseTimetablePDF } from '../../utils/timetableParser';

export const PDFImportModal = ({ isOpen, onClose, onSaved, branches, sems, subjects }) => {
  const { user } = useAuth();

  const [step, setStep] = useState(1);
  const [file, setFile] = useState(null);
  const [branch, setBranch] = useState(branches[0]?.name || '');
  const [sem, setSem] = useState('1');

  const [isScanning, setIsScanning] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const [parsedData, setParsedData] = useState(null);
  const [editableGrid, setEditableGrid] = useState([]);
  const [unmatchedSubjects, setUnmatchedSubjects] = useState([]);

  // For individual cell editing
  const [editingCell, setEditingCell] = useState(null);
  const [cellSubject, setCellSubject] = useState('');
  const [cellRoom, setCellRoom] = useState('');

  useEffect(() => {
    if (isOpen) {
      setStep(1);
      setFile(null);
      setParsedData(null);
      setUnmatchedSubjects([]);
      if (!branch && branches && branches.length > 0) {
        setBranch(branches[0].name);
      }
    }
  }, [isOpen, branches, branch]);

  const handleFileChange = (e) => {
    if (e.target.files && e.target.files.length > 0) {
      setFile(e.target.files[0]);
    }
  };

  const handleScan = async () => {
    if (!file) { toast.error("Please select a file"); return; }
    if (!branch) { toast.error("Please select a branch"); return; }
    if (!sem) { toast.error("Please select a semester"); return; }

    setStep(3);
    setIsScanning(true);
    try {
      const result = await parseTimetablePDF(file);
      setParsedData(result);

      if (result.slots.length === 0) {
        setStep(5);
      } else {
        // Build editable grid state
        const grid = [];
        const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        DAYS.forEach(d => {
          const row = { day: d, slots: Array(8).fill(null) };
          for (let i=1; i<=8; i++) {
             const found = result.slots.find(s => s.day === d && s.lecture_no === i);
             if (found) {
               row.slots[i-1] = { subject_code: found.subject_code, room: found.room };
             }
          }
          grid.push(row);
        });
        setEditableGrid(grid);
        setStep(4);
      }
    } catch (err) {
      console.error(err);
      toast.error('Failed to parse PDF: ' + err.message);
      setStep(5);
    } finally {
      setIsScanning(false);
    }
  };

  const updateCellRealtime = (subjectVal, roomVal, dayIdx, colIdx) => {
    const newGrid = [...editableGrid];
    if (!subjectVal.trim() && !roomVal.trim()) {
      newGrid[dayIdx].slots[colIdx] = null;
    } else {
      newGrid[dayIdx].slots[colIdx] = {
        subject_code: subjectVal,
        room: roomVal
      };
    }
    setEditableGrid(newGrid);
  };

  const handleSaveToDB = async () => {
    if (!confirm(`This will overwrite existing timetable slots for ${branch} Sem ${sem}. Continue?`)) return;

    setStep(6);
    setIsSaving(true);
    let successCount = 0;
    let unmatched = new Set();

    try {
      // Collect valid slots from grid
      const slotsToSave = [];
      editableGrid.forEach(row => {
        row.slots.forEach((cell, idx) => {
          if (cell) {
             slotsToSave.push({
               day: row.day,
               lecture_no: idx + 1,
               subject_code: cell.subject_code,
               room: cell.room
             });
          }
        });
      });

      for (let slot of slotsToSave) {
        // Find subject ID case-insensitive
        const matchedSubj = subjects.find(s => s.code.toLowerCase() === slot.subject_code.toLowerCase());
        let subject_id = null;

        if (matchedSubj) {
          subject_id = matchedSubj.id;
        } else {
          unmatched.add(slot.subject_code);
        }

        const { error } = await supabase.from('timetable').upsert({
          branch,
          sem: parseInt(sem),
          day_of_week: slot.day,
          lecture_no: slot.lecture_no,
          subject_id,
          room: slot.room,
          teacher_id: null // Require manual teacher assignment later or map subject_assignments
        }, { onConflict: 'branch,sem,day_of_week,lecture_no' });

        if (error) throw error;

        await supabase.from('timetable_change_log').insert({
          branch, sem: parseInt(sem), day_of_week: slot.day, lecture_no: slot.lecture_no,
          changed_by: user.id,
          change_description: `Imported ${slot.subject_code} from PDF`
        });

        successCount++;
      }

      setUnmatchedSubjects(Array.from(unmatched));
      toast.success(`${successCount} slots imported successfully.`);
      setStep(7);

    } catch (err) {
      console.error(err);
      toast.error('Error saving to DB: ' + err.message);
      setStep(4);
    } finally {
      setIsSaving(false);
    }
  };

  const renderContent = () => {
    if (step === 1 || step === 2) {
      return (
        <div className="space-y-5">
          <div className="bg-blue-50 border border-blue-200 text-blue-800 p-3 rounded text-sm flex gap-3">
            <InfoIcon className="w-5 h-5 text-blue-500 shrink-0" />
            <p>This works best with digitally created PDFs (Word/Excel exports). Scanned or photographed timetables may not be detected correctly.</p>
          </div>

          <div className="border-2 border-dashed border-slate-300 rounded-lg p-8 flex flex-col items-center justify-center bg-slate-50 relative">
            <input 
              type="file" 
              accept=".pdf" 
              onChange={handleFileChange} 
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            />
            <FileDown className="w-10 h-10 text-slate-400 mb-3" />
            {file ? (
              <p className="text-sm font-semibold text-indigo-700">{file.name}</p>
            ) : (
              <>
                <p className="text-sm font-medium text-slate-700">Drag PDF here or click to browse</p>
                <p className="text-xs text-slate-500 mt-1">Accepts .pdf files only</p>
              </>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-1">Target Branch</label>
              <select className="w-full border-slate-300 rounded p-2 text-sm" value={branch} onChange={e => setBranch(e.target.value)}>
                {branches.map(b => <option key={b.id} value={b.name}>{b.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">Target Semester</label>
              <select className="w-full border-slate-300 rounded p-2 text-sm" value={sem} onChange={e => setSem(e.target.value)}>
                {[1,2,3,4,5,6,7,8].map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
          </div>

          <div className="flex justify-end gap-2 pt-2">
            <Button variant="ghost" onClick={onClose}>Cancel</Button>
            <Button disabled={!file} onClick={handleScan}>Scan PDF</Button>
          </div>
        </div>
      );
    }

    if (step === 3 || step === 6) {
      return (
        <div className="py-12 flex flex-col items-center justify-center space-y-4">
          <RefreshCw className="w-10 h-10 text-indigo-600 animate-spin" />
          <p className="font-medium text-slate-700">
            {step === 3 ? 'Reading PDF... this may take a few seconds' : 'Saving to Database...'}
          </p>
          {step === 3 && (
            <div className="text-xs text-slate-500 space-y-1 text-center">
              <p>✓ Loading PDF</p>
              <p className="animate-pulse">⟳ Extracting table coordinates...</p>
            </div>
          )}
        </div>
      );
    }

    if (step === 5) {
      return (
        <div className="space-y-4">
          <div className="bg-red-50 border border-red-200 p-4 rounded-lg flex gap-3">
            <AlertTriangle className="w-5 h-5 text-red-500 shrink-0 mt-0.5" />
            <div>
              <h4 className="font-bold text-red-800">Could not detect timetable structure.</h4>
              <ul className="text-sm text-red-700 mt-2 space-y-1 list-disc pl-4">
                <li>Make sure the PDF was created digitally, not scanned.</li>
                <li>Try copy-pasting the timetable text into a Word doc and re-exporting as PDF.</li>
                <li>Or fill the timetable manually using the grid.</li>
              </ul>
            </div>
          </div>
          <div className="flex justify-end pt-2">
            <Button onClick={onClose}>Close</Button>
          </div>
        </div>
      );
    }

    if (step === 4) {
      let count = 0;
      editableGrid.forEach(r => { r.slots.forEach(s => { if(s) count++ }) });

      return (
        <div className="space-y-4 max-h-[80vh] flex flex-col">
          <div className="flex items-center justify-between">
            <h4 className="font-semibold text-slate-800 flex items-center gap-2">
              <CheckCircle2 className="w-5 h-5 text-green-500" />
              Preview Grid
            </h4>
            <span className="text-sm text-slate-500">{count} slots detected • {parsedData?.confidence} confidence</span>
          </div>

          <p className="text-xs text-slate-500 px-1">
            Review all cells before saving. Incorrect detections can be fixed by clicking any cell.
          </p>

          <div className="flex-1 overflow-auto border border-slate-200 rounded">
            <table className="w-full text-xs text-left min-w-[600px]">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="p-2 border-r sticky left-0 bg-slate-50">DAY</th>
                  {[1,2,3,4,5,6,7,8].map(l => <th key={l} className="p-2 border-r text-center">Lec {l}</th>)}
                </tr>
              </thead>
              <tbody>
                {editableGrid.map((row, rIdx) => (
                  <tr key={row.day} className="border-b last:border-0 hover:bg-slate-50">
                    <td className="p-2 border-r font-medium sticky left-0 bg-white">{row.day.substring(0,3)}</td>
                    {row.slots.map((cell, cIdx) => (
                      <td key={cIdx} 
                          className="p-1 border-r text-center cursor-pointer hover:bg-indigo-50 relative group"
                          onClick={() => {
                            setCellSubject(cell?.subject_code || '');
                            setCellRoom(cell?.room || '');
                            setEditingCell({ dayIdx: rIdx, colIdx: cIdx });
                          }}>
                        {cell ? (
                          <div className="flex flex-col items-center">
                            <span className="font-bold text-slate-800 truncate max-w-[60px]">{cell.subject_code}</span>
                            {cell.room && <span className="text-[9px] text-slate-500 truncate max-w-[60px]">{cell.room}</span>}
                          </div>
                        ) : <span className="text-slate-300">—</span>}

                        {/* Editor popover */}
                        {editingCell?.dayIdx === rIdx && editingCell?.colIdx === cIdx && (
                          <div className="absolute top-full left-1/2 -translate-x-1/2 mt-1 w-48 bg-white shadow-xl border border-slate-200 rounded p-2 z-50 text-left cursor-default" onClick={e=>e.stopPropagation()}>
                            <div className="flex justify-between items-center bg-slate-50 -mx-2 -mt-2 p-2 mb-2 border-b">
                              <span className="font-semibold text-slate-700">Edit Slot</span>
                              <X className="w-4 h-4 cursor-pointer" onClick={() => setEditingCell(null)} />
                            </div>
                            <div className="space-y-2">
                              <input 
                                type="text" 
                                placeholder="Subject Code (e.g. DBMS)" 
                                className="w-full text-xs p-1 border rounded focus:ring-1 focus:ring-indigo-500 outline-none" 
                                value={cellSubject} 
                                onChange={e => {
                                  setCellSubject(e.target.value);
                                  updateCellRealtime(e.target.value, cellRoom, rIdx, cIdx);
                                }} 
                              />
                              <input 
                                type="text" 
                                placeholder="Room (optional)" 
                                className="w-full text-xs p-1 border rounded focus:ring-1 focus:ring-indigo-500 outline-none" 
                                value={cellRoom} 
                                onChange={e => {
                                  setCellRoom(e.target.value);
                                  updateCellRealtime(cellSubject, e.target.value, rIdx, cIdx);
                                }} 
                              />
                              <div className="flex gap-2 pt-1 border-t mt-2 top-2 pt-2">
                                <Button variant="ghost" size="sm" onClick={() => {
                                  setCellSubject('');
                                  setCellRoom('');
                                  updateCellRealtime('', '', rIdx, cIdx);
                                }} className="w-full h-7 text-xs text-red-500 hover:bg-red-50 hover:text-red-600">Clear Cell</Button>
                                <Button size="sm" onClick={() => setEditingCell(null)} className="w-full h-7 text-xs">Done</Button>
                              </div>
                            </div>
                          </div>
                        )}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <div className="flex justify-between items-center pt-2 border-t">
            <Button variant="ghost" onClick={() => setStep(1)}>Back</Button>
            <div className="flex gap-2">
              <Button variant="outline" onClick={onClose}>Cancel</Button>
              <Button onClick={handleSaveToDB}>Save to Timetable</Button>
            </div>
          </div>
        </div>
      );
    }

    if (step === 7) {
      return (
        <div className="space-y-4">
          <div className="py-6 flex flex-col items-center">
            <CheckCircle2 className="w-12 h-12 text-green-500 mb-2" />
            <h3 className="text-lg font-bold text-slate-800">Import Successful</h3>
          </div>

          {unmatchedSubjects.length > 0 && (
            <div className="bg-amber-50 border border-amber-200 p-4 rounded-lg">
              <h4 className="font-bold text-amber-800 flex items-center gap-2 text-sm mb-2">
                <AlertCircle className="w-4 h-4" />
                Unmatched Subjects
              </h4>
              <p className="text-xs text-amber-700 mb-2">
                The following subject codes were imported but not found in your Subject Management database. 
                They have been saved without linking to a master subject:
              </p>
              <div className="flex flex-wrap gap-1">
                {unmatchedSubjects.map(s => <span key={s} className="bg-white border border-amber-300 text-amber-800 text-[10px] px-2 py-0.5 rounded font-bold">{s}</span>)}
              </div>
            </div>
          )}

          <div className="flex justify-end pt-4">
            <Button onClick={() => { onClose(); onSaved(); }}>Done</Button>
          </div>
        </div>
      );
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Import Timetable from PDF" className="max-w-3xl">
      {renderContent()}
    </Modal>
  );
};

const InfoIcon = ({ className }) => (
  <svg className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
  </svg>
);

import React, { useState, useRef, useEffect } from 'react';
import ReactCrop from 'react-image-crop';
import 'react-image-crop/dist/ReactCrop.css';
import { Button } from '../ui/Button';
import { toast } from '../ui/Toast';
import * as pdfjsLib from 'pdfjs-dist';

// Configure pdf.js worker
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js`;

export const TimetableCropper = ({ onCropComplete, onCancel }) => {
  const [upImg, setUpImg] = useState();
  const imgRef = useRef(null);
  const [crop, setCrop] = useState({ unit: '%', width: 50, height: 50, x: 25, y: 25 });
  const [completedCrop, setCompletedCrop] = useState(null);

  const [isProcessingPdf, setIsProcessingPdf] = useState(false);

  const onSelectFile = async (e) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];

      if (file.type === 'application/pdf') {
        setIsProcessingPdf(true);
        try {
          const arrayBuffer = await file.arrayBuffer();
          const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
          const page = await pdf.getPage(1);

          const viewport = page.getViewport({ scale: 2.5 }); // High scale for clear crop
          const canvas = document.createElement('canvas');
          canvas.height = viewport.height;
          canvas.width = viewport.width;
          const context = canvas.getContext('2d');

          await page.render({ canvasContext: context, viewport }).promise;
          setUpImg(canvas.toDataURL('image/png'));
        } catch (err) {
          console.error(err);
          toast.error('Could not process PDF. Make sure it is valid.');
        } finally {
          setIsProcessingPdf(false);
        }
      } else {
        const reader = new FileReader();
        reader.addEventListener('load', () => setUpImg(reader.result));
        reader.readAsDataURL(file);
      }
    }
  };

  const onLoad = (e) => { imgRef.current = e.currentTarget; };

  const generateCroppedImage = async () => {
    if (!completedCrop || !imgRef.current) return;
    const image = imgRef.current;
    if (!completedCrop.width || !completedCrop.height) {
        onCancel();
        return;
    }
    const canvas = document.createElement('canvas');
    const scaleX = image.naturalWidth / image.width;
    const scaleY = image.naturalHeight / image.height;
    canvas.width = completedCrop.width * scaleX;
    canvas.height = completedCrop.height * scaleY;
    const ctx = canvas.getContext('2d');

    ctx.imageSmoothingQuality = "high";
    ctx.drawImage(
      image,
      completedCrop.x * scaleX,
      completedCrop.y * scaleY,
      completedCrop.width * scaleX,
      completedCrop.height * scaleY,
      0,
      0,
      canvas.width,
      canvas.height
    );

    canvas.toBlob((blob) => {
      if (!blob) return;
      onCropComplete(blob);
    }, 'image/png');
  };

  return (
    <div className="flex flex-col gap-4">
      {!upImg && (
        <div className="flex flex-col items-center justify-center p-8 border-2 border-dashed border-slate-300 rounded-lg bg-slate-50">
          <input type="file" accept="image/*,.pdf" onChange={onSelectFile} disabled={isProcessingPdf} className="mb-4 text-sm file:mr-4 file:py-2 file:px-4 file:rounded file:border-0 file:bg-indigo-50 file:text-indigo-700 hover:file:bg-indigo-100" />
          <p className="text-sm text-slate-500 font-medium">
            {isProcessingPdf ? 'Extracting PDF page...' : 'Upload Image or PDF of the timetable'}
          </p>
        </div>
      )}
      {upImg && (
        <div className="flex flex-col gap-4">
          <div className="max-h-[60vh] max-w-full overflow-auto border border-slate-200">
            <ReactCrop
              crop={crop}
              onChange={(c) => setCrop(c)}
              onComplete={(c) => setCompletedCrop(c)}
            >
              <img src={upImg} onLoad={onLoad} alt="Timetable to crop" style={{maxWidth: '100%'}}/>
            </ReactCrop>
          </div>
          <div className="flex justify-end gap-2 mt-4">
             <Button variant="ghost" onClick={onCancel}>Cancel</Button>
             <Button onClick={generateCroppedImage}>Crop & Save Image</Button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import { toast } from '../ui/Toast';
import { Modal } from '../ui/Modal';
import { Button } from '../ui/Button';
import { Badge } from '../ui/Badge';
import { Info, UserCheck, Coffee, Trash2 } from 'lucide-react';

const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];

const CellEditor = ({ slotInfo, onClose, onSave, isAuthorized }) => {
  const [subjectId, setSubjectId] = useState(slotInfo.subject_id || '');
  const [subjects, setSubjects] = useState([]);

  useEffect(() => {
    const fetchSubjects = async () => {
      const { data } = await supabase.from('subjects').select('id, code, name');
      if (data) setSubjects(data);
    };
    fetchSubjects();
  }, []);

  return (
    <div className="p-4 bg-white rounded-md space-y-4">
      <div>
        <label className="text-sm font-medium">Subject</label>
        <select 
          className="w-full mt-1 border border-slate-300 rounded px-2 py-1 bg-slate-50 disabled:opacity-70"
          value={subjectId}
          onChange={(e) => setSubjectId(e.target.value)}
          disabled={!isAuthorized}
        >
          <option value="">Select Subject...</option>
          {subjects.map(s => <option key={s.id} value={s.id}>{s.code} - {s.name}</option>)}
        </select>
      </div>
      {isAuthorized && (
        <div className="flex justify-between items-center pt-2">
          {slotInfo.subject_id && (
            <Button 
              variant="ghost" 
              className="text-red-500 hover:bg-red-50" 
              size="sm"
              onClick={() => onSave({ ...slotInfo, subject_id: null, room: null })}
            >
              <Trash2 className="h-4 w-4 mr-1" />
              Clear
            </Button>
          )}
          <div className="flex gap-2 ml-auto">
            <Button variant="ghost" onClick={onClose} size="sm">Cancel</Button>
            <Button onClick={() => onSave({ ...slotInfo, subject_id: subjectId, room: null })} size="sm">Save</Button>
          </div>
        </div>
      )}
    </div>
  );
};

export const TimetableGrid = ({ branch, sem, editable = false }) => {
  const { role, user } = useAuth();
  const [slots, setSlots] = useState(8);
  const [timetable, setTimetable] = useState([]);
  const [substitutes, setSubstitutes] = useState([]);
  const [leaves, setLeaves] = useState([]);
  const [changeLogs, setChangeLogs] = useState({});
  const [editingCell, setEditingCell] = useState(null);
  const [loading, setLoading] = useState(true);
  const [assignedSubjects, setAssignedSubjects] = useState([]);

  const fetchData = async () => {
    setLoading(true);
    // 1. Get config
    const { data: config } = await supabase.from('system_config').select('*').eq('key', 'lectures_per_day').single();
    if (config) setSlots(parseInt(config.value));

    // 2. Get assigned subjects if teacher
    if (role === 'teacher') {
      const { data: assignments } = await supabase.from('subject_assignments').select('subject_id').eq('teacher_id', user.id);
      if (assignments) setAssignedSubjects(assignments.map(a => a.subject_id));
    }

    if (branch && sem) {
      // 2. Get timetable
      const { data: ttData } = await supabase
        .from('timetable')
        .select(`
          *,
          subjects (id, code, name),
          users:teacher_id (name)
        `)
        .eq('branch', branch)
        .eq('sem', sem);
      if (ttData) setTimetable(ttData);

      // 3. Get substitutes for today
      const today = new Date().toISOString().split('T')[0];
      const { data: subData } = await supabase
        .from('substitute_log')
        .select('*')
        .eq('date', today)
        .eq('status', 'accepted');
      if (subData) setSubstitutes(subData);

      // 4. Get leaves
      const { data: leaveData } = await supabase
        .from('leave_requests')
        .select('*')
        .eq('date', today)
        .eq('status', 'approved');
      if (leaveData) setLeaves(leaveData);

      // 5. Get change logs for all slots
      const { data: logs } = await supabase
        .from('timetable_change_log')
        .select('*, users(name)')
        .eq('branch', branch)
        .eq('sem', sem)
        .order('changed_at', { ascending: false });

      const logsBySlot = {};
      logs?.forEach(log => {
        const key = `${log.day_of_week}-${log.lecture_no}`;
        if (!logsBySlot[key]) logsBySlot[key] = [];
        if (logsBySlot[key].length < 3) logsBySlot[key].push(log);
      });
      setChangeLogs(logsBySlot);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, [branch, sem]);

  const handleSaveCell = async (updatedSlot) => {
    setLoading(true);
    try {
      const isUpdate = !!timetable.find(t => t.day_of_week === updatedSlot.day_of_week && t.lecture_no === updatedSlot.lecture_no);

      let subject = null;
      let teacher_id = null;

      if (updatedSlot.subject_id) {
        // 1. Get subject details for logging
        const { data: sub } = await supabase.from('subjects').select('name').eq('id', updatedSlot.subject_id).single();
        subject = sub;

        // 2. Automatically get the assigned teacher for this subject for the timetable record
        const { data: assignment } = await supabase
          .from('subject_assignments')
          .select('teacher_id')
          .eq('subject_id', updatedSlot.subject_id)
          .maybeSingle();

        teacher_id = assignment?.teacher_id || null;
      }

      const { error } = await supabase.from('timetable').upsert({
        branch,
        sem,
        day_of_week: updatedSlot.day_of_week,
        lecture_no: updatedSlot.lecture_no,
        subject_id: updatedSlot.subject_id || null,
        room: updatedSlot.room,
        teacher_id: teacher_id // Save the teacher association
      }, { onConflict: 'branch,sem,day_of_week,lecture_no' });

      if (error) throw error;

      // Log the change
      await supabase.from('timetable_change_log').insert({
        branch,
        sem,
        day_of_week: updatedSlot.day_of_week,
        lecture_no: updatedSlot.lecture_no,
        changed_by: user.id,
        change_description: isUpdate ? `Updated to ${subject?.name || 'Empty'}` : `Set to ${subject?.name || 'Empty'}`
      });

      toast.success('Slot updated');
      setEditingCell(null);
      fetchData();
    } catch (error) {
      console.error(error);
      toast.error('Failed to update slot: ' + (error.message || 'Database error'));
    } finally {
      setLoading(false);
    }
  };



  const getCellData = (day, lecNo) => {
    return timetable.find(t => t.day_of_week === day && t.lecture_no === lecNo);
  };

  const currentDay = new Date().toLocaleDateString('en-US', { weekday: 'long' });

  if (loading) return <div className="p-8 text-center text-slate-500">Loading timetable...</div>;
  if (!branch || !sem) return <div className="p-4 text-center text-slate-500 border rounded-lg bg-slate-50">Select Branch and Sem to view timetable.</div>;

  return (
    <div className="space-y-4">
      <div className="overflow-x-auto border border-slate-200 rounded-md bg-white">
      <table className="w-full text-sm text-left table-fixed">
        <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200">
          <tr>
            <th className="w-24 px-4 py-3 border-r border-slate-200 sticky left-0 bg-slate-50 z-10 text-xs text-slate-500 font-bold uppercase tracking-wider">DAY</th>
            {Array.from({ length: slots }).map((_, i) => (
              <th key={i} className="px-4 py-3 text-center border-r border-slate-200 w-32 text-xs text-slate-500 font-bold uppercase tracking-wider">Lec {i + 1}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {DAYS.map(day => (
            <tr key={day} className={`border-b border-slate-200 ${day === currentDay ? 'bg-indigo-50/40' : 'bg-white'}`}>
              <td className="px-4 py-4 border-r border-slate-200 font-bold text-slate-700 sticky left-0 bg-inherit shadow-[1px_0_0_0_#e2e8f0] z-10 text-xs">
                {day.toUpperCase()}
              </td>
              {Array.from({ length: slots }).map((_, i) => {
                const lecNo = i + 1;
                const cellData = getCellData(day, lecNo);
                const isAuthorizedToEdit = role === 'admin' || role === 'hod';

                const hasSubstitute = substitutes.find(s => s.timetable_id === cellData?.id);
                const teacherOnLeave = leaves.find(l => l.teacher_id === cellData?.teacher_id);
                const logs = changeLogs[`${day}-${lecNo}`] || [];

                return (
                  <td 
                    key={lecNo} 
                    className={`border-r border-slate-200 p-2 relative group transition-colors ${isAuthorizedToEdit && editable ? 'cursor-pointer hover:bg-slate-100/50' : ''}`}
                    onClick={() => {
                      if (editable && isAuthorizedToEdit) {
                        setEditingCell({
                          day_of_week: day,
                          lecture_no: lecNo,
                          subject_id: cellData?.subject_id,
                          room: null
                        });
                      }
                    }}
                  >
                    <div className="flex flex-col items-center justify-center h-20 rounded border border-transparent group-hover:border-slate-200">
                      {cellData?.subjects ? (
                        <>
                          <span className="font-bold text-slate-900 text-xs">{cellData.subjects.code}</span>
                          <span className="text-[10px] text-slate-500 text-center leading-tight max-w-[7rem] truncate px-1">{cellData.subjects.name}</span>
                          <div className="flex gap-1 mt-1">
                            {hasSubstitute && <Badge variant="indigo" className="px-1 py-0"><UserCheck className="h-3 w-3" /></Badge>}
                            {teacherOnLeave && <Badge variant="warning" className="px-1 py-0"><Coffee className="h-3 w-3" /></Badge>}
                          </div>
                        </>
                      ) : (
                        <span className="text-slate-200 font-light">—</span>
                      )}
                    </div>

                    {/* Change Log Tooltip */}
                    {logs.length > 0 && (
                      <div className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 transition-opacity z-20">
                        <div className="relative group/tooltip">
                          <Info className="h-3.5 w-3.5 text-slate-300 cursor-help hover:text-indigo-500 transition-colors" />
                          <div className="absolute bottom-full right-0 mb-2 w-52 p-2 bg-slate-900 text-white text-[10px] rounded shadow-2xl hidden group-hover/tooltip:block z-30">
                             <p className="font-bold border-b border-slate-700 pb-1 mb-1 uppercase tracking-tighter text-[9px] text-indigo-300">Recent Changes</p>
                             {logs.map((log, idx) => (
                               <p key={idx} className="mb-1 last:mb-0 leading-tight">
                                 <span className="text-slate-400 font-medium">{new Date(log.changed_at).toLocaleDateString('en-IN')}:</span> {log.change_description} by {log.users?.name}
                               </p>
                             ))}
                          </div>
                        </div>
                      </div>
                    )}
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
      </div>

      <Modal isOpen={!!editingCell} onClose={() => setEditingCell(null)} title="Schedule Lecture">
        {editingCell && (
          <CellEditor 
            slotInfo={editingCell} 
            onClose={() => setEditingCell(null)} 
            onSave={handleSaveCell}
            isAuthorized={role === 'admin' || role === 'hod'} 
          />
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Badge } from './Badge';
import { Bell, Pin, Calendar, User, ChevronDown, ChevronUp } from 'lucide-react';

export const NoticeBoard = ({ branch, sem, role }) => {
  const [notices, setNotices] = useState([]);
  const [archived, setArchived] = useState([]);
  const [showArchive, setShowArchive] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchNotices = async () => {
      setLoading(true);
      let query = supabase
        .from('notices')
        .select('*, users(name)')
        .eq('is_active', true)
        .order('is_pinned', { ascending: false })
        .order('created_at', { ascending: false });

      if (branch) query = query.in('branch', [branch, 'All']);
      if (sem) query = query.in('sem', [sem, 0]); // 0 for all sems

      const { data } = await query;

      if (data) {
        // Separate active and archived (we consider notices older than 30 days archived for UI purposes, or just use stays active)
        // Actually, the spec says "Archive collapsed at bottom". 
        // Let's take the first 10 as active, rest as archive? Or use a specific flag?
        // Usually notices have an expiration or just manual deactivation.
        // Let's assume the top 5 are "Current" and the rest are "Recent".
        setNotices(data.slice(0, 5));
        setArchived(data.slice(5));
      }
      setLoading(false);
    };

    fetchNotices();
  }, [branch, sem]);

  const getTypeColor = (type) => {
    switch (type.toLowerCase()) {
      case 'assignment': return 'red';
      case 'lab': return 'indigo';
      case 'library': return 'slate';
      default: return 'green';
    }
  };

  const NoticeCard = ({ notice }) => (
    <div className={`p-4 rounded-lg border bg-white shadow-sm transition-all hover:shadow-md ${notice.is_pinned ? 'border-indigo-200 bg-indigo-50/10' : 'border-slate-100'}`}>
      <div className="flex justify-between items-start mb-2">
        <div className="flex items-center gap-2">
          {notice.is_pinned && <Pin className="h-4 w-4 text-indigo-600 fill-indigo-600" />}
          <Badge variant={getTypeColor(notice.type)} className="uppercase text-[10px]">
            {notice.type}
          </Badge>
        </div>
        <span className="text-[10px] text-slate-400 flex items-center gap-1">
          <Calendar className="h-3 w-3" />
          {new Date(notice.created_at).toLocaleDateString('en-IN')}
        </span>
      </div>
      <h4 className="font-semibold text-slate-800 mb-1">{notice.title}</h4>
      <p className="text-sm text-slate-600 line-clamp-3 mb-3">{notice.body}</p>
      <div className="flex items-center justify-between mt-auto pt-2 border-t border-slate-50">
        <span className="text-xs text-slate-500 flex items-center gap-1">
          <User className="h-3 w-3" />
          {notice.users?.name || 'System'}
        </span>
        {notice.due_date && (
          <span className="text-xs font-medium text-red-600">
            Due: {new Date(notice.due_date).toLocaleDateString('en-IN')}
          </span>
        )}
      </div>
    </div>
  );

  if (loading) return <div className="p-8 text-center text-slate-500">Loading notices...</div>;

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-2 text-slate-700 mb-2">
        <Bell className="h-5 w-5 text-indigo-600" />
        <h3 className="font-bold uppercase tracking-wider text-sm">Notice Board</h3>
      </div>

      {notices.length === 0 ? (
        <div className="p-8 text-center bg-slate-50 rounded-lg border border-dashed border-slate-200">
          <p className="text-sm text-slate-500">No active notices for your branch/sem.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-4">
          {notices.map(n => <NoticeCard key={n.id} notice={n} />)}
        </div>
      )}

      {archived.length > 0 && (
        <div className="mt-6">
          <button 
            onClick={() => setShowArchive(!showArchive)}
            className="flex items-center gap-2 text-xs font-medium text-slate-500 hover:text-slate-800 transition-colors"
          >
            {showArchive ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
            {showArchive ? 'Hide Archive' : `Show ${archived.length} Older Notices`}
          </button>

          {showArchive && (
            <div className="grid grid-cols-1 gap-4 mt-4 opacity-80">
              {archived.map(n => <NoticeCard key={n.id} notice={n} />)}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

