                                        Provision Account
                                    </Button>
                                </div>
                            </form>
                        </div>
                    )}
                </div>

                <div className="space-y-6">
                    <div className="panel p-6 bg-slate-900 border-none shadow-2xl relative overflow-hidden text-white">
                        <div className="absolute top-0 right-0 p-4 opacity-5 bg-gradient-to-br from-white to-transparent rounded-full h-32 w-32 -mr-16 -mt-16" />
                        <h3 className="font-bold flex items-center gap-2 mb-6">
                            <History className="h-4 w-4 text-indigo-400" />
                            Audit History
                        </h3>
                        <div className="space-y-4">
                            {history.slice(0, 5).map(h => (
                                <div key={h.id} className="flex items-start gap-3 p-3 bg-white/5 border border-white/10 rounded-2xl hover:bg-white/10 transition-colors">
                                    <div className={`w-1.5 h-1.5 rounded-full mt-1.5 shrink-0 ${h.status === 'success' ? 'bg-green-400' : 'bg-amber-400'}`} />
                                    <div className="min-w-0">
                                        <p className="text-[10px] font-black uppercase text-slate-500">{new Date(h.created_at).toLocaleDateString()}</p>
                                        <p className="text-xs font-bold truncate text-slate-100">{h.file_name || 'Manual Provisioning'}</p>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="panel p-6 bg-indigo-50 border-indigo-100">
                        <h4 className="text-[10px] font-black text-indigo-900 uppercase tracking-widest mb-3 flex items-center gap-2">
                            <GraduationCap className="h-4 w-4" /> Security Note
                        </h4>
                        <p className="text-[11px] text-indigo-800 leading-relaxed font-medium">
                            Every user created here is automatically synchronized with Supabase Auth. Initial password is set to their College ID.
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { StatCard } from '../../components/ui/StatCard';
import { Table } from '../../components/ui/Table';
import { Badge } from '../../components/ui/Badge';
import { Button } from '../../components/ui/Button';
import { 
  Users, BookOpen, GraduationCap, Bell, UserPlus, 
  Upload, Calendar, ArrowRightLeft, ShieldCheck, 
  Activity, AlertCircle, RefreshCw
} from 'lucide-react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';

export const AdminDashboard = () => {
  const [stats, setStats] = useState({ students: 0, teachers: 0, hods: 0, branches: 0 });
  const [healthStatus, setHealthStatus] = useState('OK');
  const [recentLogs, setRecentLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const { role } = useAuth();

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      const [studentsRes, teachersRes, hodsRes, branchesRes, healthRes] = await Promise.all([
        supabase.from('students').select('*', { count: 'exact', head: true }),
        supabase.from('users').select('*', { count: 'exact', head: true }).eq('role', 'teacher'),
        supabase.from('users').select('*', { count: 'exact', head: true }).eq('role', 'hod'),
        supabase.from('branches').select('*', { count: 'exact', head: true }),
        supabase.rpc('get_system_health')
      ]);
      
      setStats({
        students: studentsRes.count || 0,
        teachers: teachersRes.count || 0,
        hods: hodsRes.count || 0,
        branches: branchesRes.count || 0,
      });

      if (healthRes.data) {
        setHealthStatus(healthRes.data.missing_from_auth > 0 ? 'Warning' : 'OK');
      }

      const { data: logs } = await supabase
        .from('bulk_upload_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(10);
      setRecentLogs(logs || []);
      setLoading(false);
    };
    fetchData();
  }, []);

  // Silent system health check on first login/load
  useEffect(() => {
    const runSilentRepair = async () => {
      try {
        const { data: health } = await supabase.rpc('get_system_health');
        if (health && (health.missing_from_auth > 0 || health.missing_identities > 0)) {
          console.info('Auto-syncing users to auth...');
          await supabase.rpc('sync_all_users_to_auth');
        }
      } catch (e) {
        console.warn('Silent health check failed:', e);
      }
    };
    
    // Only run once per session
    const hasChecked = sessionStorage.getItem('health_checked');
    if (!hasChecked) {
      runSilentRepair();
      sessionStorage.setItem('health_checked', 'true');
    }
  }, []);

  const logColumns = [
    { header: 'File Name', accessor: 'file_name' },
    { header: 'Type', accessor: 'type', render: (row) => <span className="capitalize">{row.type}</span> },
    {
      header: 'Status',
      accessor: 'status',
      render: (row) => (
        <Badge variant={row.status === 'success' ? 'success' : row.status === 'failed' ? 'danger' : 'warning'}>
          {row.status.toUpperCase()}
        </Badge>
      ),
    },
    {
      header: 'Date',
      accessor: 'created_at',
      render: (row) => new Date(row.created_at).toLocaleDateString('en-IN'),
    },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Admin Console</h2>
          <p className="text-slate-500 mt-1 font-medium">System-wide oversight & infrastructure management.</p>
        </div>
        <div className="flex gap-2">
          <Badge variant={healthStatus === 'OK' ? 'success' : 'danger'} className="h-8 px-3 flex items-center gap-2">
            <ShieldCheck className="h-4 w-4" />
            System {healthStatus}
          </Badge>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard title="Total Students" value={loading ? '...' : stats.students} icon={GraduationCap} color="indigo" />
        <StatCard title="Total Teachers" value={loading ? '...' : stats.teachers} icon={Users} color="slate" />
        <StatCard title="Total HODs" value={loading ? '...' : stats.hods} icon={Briefcase} color="slate" />
        <StatCard title="Active Branches" value={loading ? '...' : stats.branches} icon={Landmark} color="indigo" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-4 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-bold text-slate-900 flex items-center gap-2">
              <Activity className="h-5 w-5 text-indigo-600" />
              Recent Activity
            </h3>
            <span className="text-xs text-slate-500 font-bold uppercase tracking-wider">Last 10 events</span>
          </div>
          <Table columns={logColumns} data={recentLogs} emptyMessage="No recent activity found." />
        </div>

        <div className="space-y-4">
          <h3 className="text-lg font-bold text-slate-900 px-2">Quick Actions</h3>
          <div className="grid grid-cols-1 gap-3">
            <QuickAction to="/admin/users" title="User Management" icon={UserPlus} desc="Create, edit, or reset accounts" />
            <QuickAction to="/admin/bulk-upload" title="Bulk Import" icon={Upload} desc="Batch import roles from Excel" />
            <QuickAction to="/admin/timetable" title="Timetable Grid" icon={Calendar} desc="Schedule slots and rooms" />
            <QuickAction to="/admin/sem-transition" title="Semester Roll" icon={ArrowRightLeft} desc="Promote students to next sem" />
            <QuickAction to="/admin/health" title="System Health" icon={ShieldCheck} desc="Repair DB sync & auth links" />
          </div>
        </div>
      </div>
    </div>
  );
};

const QuickAction = ({ to, title, icon: Icon, desc }) => (
  <Link to={to} className="flex items-center gap-4 p-4 bg-white rounded-xl border border-slate-200 hover:border-indigo-300 hover:shadow-md hover:shadow-indigo-50 transition-all group">
    <div className="p-3 rounded-lg bg-slate-50 text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-colors">
      <Icon className="h-6 w-6" />
    </div>
    <div>
      <h4 className="font-bold text-slate-800 group-hover:text-indigo-600 transition-colors">{title}</h4>
      <p className="text-xs text-slate-500 font-medium">{desc}</p>
    </div>
  </Link>
);

const Briefcase = (props) => (
  <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="7" width="20" height="14" rx="2" ry="2"></rect><path d="M16 21V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v16"></path></svg>
);

const Landmark = (props) => (
  <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="2" y1="22" x2="22" y2="22"></line><path d="M18 12V7"></path><path d="M12 12V7"></path><path d="M6 12V7"></path><path d="M2 7L12 2l10 5"></path><path d="M4 22V12h16v10"></path></svg>
);

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { toast } from '../../components/ui/Toast';
import { StatCard } from '../../components/ui/StatCard';
import { Badge } from '../../components/ui/Badge';
import { Table } from '../../components/ui/Table';
import { 
  ShieldCheck, RefreshCw, Database, AlertCircle, 
  Users, GraduationCap, HardDrive, Download, Search
} from 'lucide-react';
import { exportToExcel } from '../../utils/exportExcel';

export const AdminSystemHealth = () => {
  const [health, setHealth] = useState(null);
  const [brokenUsers, setBrokenUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(null);

  const fetchHealth = async () => {
    setLoading(true);
    const [hRes, bRes] = await Promise.all([
      supabase.rpc('get_system_health'),
      supabase.rpc('get_broken_users')
    ]);

    if (hRes.data) setHealth(hRes.data);
    if (bRes.data) setBrokenUsers(bRes.data);

    setLoading(false);
  };

  useEffect(() => {
    fetchHealth();
  }, []);

  const handleMaintenance = async (method, label) => {
    setActionLoading(label);
    try {
      const { error } = await supabase.rpc(method);
      if (error) throw error;
      toast.success(`${label} completed successfully`);
      await fetchHealth();
    } catch (err) {
      toast.error(`Error: ${err.message}`);
    } finally {
      setActionLoading(null);
    }
  };

  const downloadCredentials = async () => {
    try {
      const { data, error } = await supabase.from('users').select('college_id, name, role, initial_password').is('deleted_at', null);
      if (error) throw error;

      exportToExcel(data, 'User_Credentials_Backup', [
        { header: 'College ID', key: 'college_id' },
        { header: 'Name', key: 'name' },
        { header: 'Role', key: 'role' },
        { header: 'Initial Password', key: 'initial_password' },
      ]);
      toast.success('Credentials exported.');
    } catch (err) {
      toast.error('Export failed');
    }
  };

  const brokenColumns = [
    { header: 'College ID', accessor: 'college_id', render: r => <span className="font-mono font-bold text-xs">{r.college_id}</span> },
    { header: 'Identity Name', accessor: 'name' },
    { header: 'Role', accessor: 'role', render: r => <Badge variant="slate" className="uppercase text-[9px]">{r.role}</Badge> },
    { 
      header: 'Detected Issue', 
      accessor: 'issue', 
      render: r => (
        <span className="flex items-center gap-1.5 text-xs font-bold text-red-600">
          <AlertCircle className="h-3.5 w-3.5" />
          {r.issue}
        </span>
      )
    },
    {
      header: 'Recovery',
      accessor: 'id',
      render: r => (
        <Button size="sm" variant="ghost" className="h-8 text-indigo-600 font-bold text-[10px]" onClick={async () => {
          setActionLoading(`Sync-${r.id}`);
          const { error } = await supabase.rpc('sync_user_to_auth', { target_id: r.id });
          if (error) toast.error('Sync failed');
          else {
            toast.success(`${r.college_id} synchronized`);
            fetchHealth();
          }
          setActionLoading(null);
        }}>
          {actionLoading === `Sync-${r.id}` ? <RefreshCw className="h-3 w-3 animate-spin" /> : 'REPAIR'}
        </Button>
      )
    }
  ];

  if (loading && !health) {
    return (
      <div className="flex flex-col items-center justify-center p-20 space-y-4">
        <RefreshCw className="h-10 w-10 text-indigo-600 animate-spin" />
        <p className="text-slate-500 font-medium">Analyzing system integrity...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <div className="flex items-center gap-2 text-indigo-600 mb-1">
            <ShieldCheck className="h-4 w-4" />
            <span className="text-[10px] font-extrabold uppercase tracking-[0.2em]">Diagnostic Terminal</span>
          </div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">System Infrastructure Health</h2>
          <p className="text-sm text-slate-500 font-medium">Monitoring synchronization between Auth and Public identity layers.</p>
        </div>
        <Button variant="outline" onClick={fetchHealth} disabled={loading} className="h-11 rounded-xl">
           <RefreshCw className={`h-4 w-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
           Recalculate Integrity
        </Button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard title="Total Users" value={health?.total_users} icon={Users} color="slate" />
        <StatCard 
          title="Missing Auth" 
          value={health?.missing_from_auth} 
          icon={AlertCircle} 
          color={health?.missing_from_auth > 0 ? "red" : "green"} 
          subtitle="Critical Repair Required"
        />
        <StatCard 
          title="Broken Ident." 
          value={health?.missing_identities} 
          icon={AlertCircle} 
          color={health?.missing_identities > 0 ? "red" : "green"} 
          subtitle="Identity mismatch"
        />
        <StatCard title="Database Size" value={`${health?.db_size_mb} MB`} icon={HardDrive} color="indigo" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
           {/* Detailed Broken Users Registry */}
           <div className="panel p-0 overflow-hidden border-slate-200 shadow-xl shadow-slate-100/50 bg-white">
              <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
                <h3 className="font-bold text-slate-900 flex items-center gap-2">
                  <Search className="h-4 w-4 text-slate-400" />
                  Synchronization Audit Logs
                </h3>
                <Badge variant={brokenUsers.length > 0 ? 'danger' : 'success'} className="px-3">
                  {brokenUsers.length} Issues Found
                </Badge>
              </div>
              <Table 
                columns={brokenColumns} 
                data={brokenUsers} 
                loading={loading}
                emptyMessage="Architecture is healthy. No synchronization issues detected."
              />
           </div>
        </div>

        <div className="lg:col-span-1 space-y-6">
            <div className="panel p-6 bg-slate-900 text-white border-none shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-5 bg-gradient-to-br from-white to-transparent rounded-full h-32 w-32 -mr-16 -mt-16" />
                <h3 className="font-bold text-lg mb-6 flex items-center gap-2">
                    <Database className="h-5 w-5 text-indigo-400" />
                    Infrastructure Toolset
                </h3>
                <div className="space-y-4">
                    <MaintenanceAction 
                        title="Atomic Identity Sync"
                        desc="Batch repairs every user identity in the background."
                        onClick={() => handleMaintenance('sync_all_users_to_auth', 'Global Sync')}
                        loading={actionLoading === 'Global Sync'}
                    />
                    <MaintenanceAction 
                        title="Credential Safe Export"
                        desc="Backup of all college IDs and initial passwords."
                        onClick={downloadCredentials}
                        variant="secondary"
                    />
                </div>
            </div>

            <div className="panel p-6 bg-indigo-50 border-indigo-100">
                <h4 className="text-[10px] font-black text-indigo-900 uppercase tracking-widest mb-3 flex items-center gap-2">
                    <AlertCircle className="h-4 w-4" /> Automated Self-Healing
                </h4>
                <p className="text-[11px] text-indigo-800 leading-relaxed font-medium">
                    The system performs a silent health check on every admin login. Manual intervention is only required if the dashboard shows red indicators above.
                </p>
            </div>
        </div>
      </div>
    </div>
  );
};

const MaintenanceAction = ({ title, desc, onClick, loading, variant = 'primary' }) => (
  <button 
    onClick={onClick}
    disabled={loading}
    className={`w-full text-left p-4 rounded-2xl border transition-all ${
        variant === 'primary' 
        ? "bg-white/5 border-white/10 hover:bg-white/10 text-white" 
        : "bg-indigo-600/10 border-indigo-500/20 hover:bg-indigo-600/20 text-indigo-400"
    }`}
  >
    <div className="flex items-center justify-between mb-1">
        <h5 className="text-sm font-bold">{title}</h5>
        {loading && <RefreshCw className="h-3 w-3 animate-spin" />}
    </div>
    <p className="text-[10px] opacity-60 font-medium leading-relaxed">{desc}</p>
  </button>
);

