import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Table } from '../../components/ui/Table';
import { Modal } from '../../components/ui/Modal';
import { toast } from '../../components/ui/Toast';
import { useAuth } from '../../hooks/useAuth';
import { Calendar, Plus, Trash2, PartyPopper } from 'lucide-react';

export const AdminHolidays = () => {
    const { user } = useAuth();
    const [holidays, setHolidays] = useState([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [formData, setFormData] = useState({
        date: '',
        reason: ''
    });

    useEffect(() => {
        fetchHolidays();
    }, []);

    async function fetchHolidays() {
        setLoading(true);
        const { data, error } = await supabase
            .from('holidays')
            .select('*')
            .order('date', { ascending: true });

        if (error) {
            toast.error('Failed to fetch holidays');
        } else {
            setHolidays(data || []);
        }
        setLoading(false);
    }

    const handleCreate = async (e) => {
        e.preventDefault();
        const { error } = await supabase.from('holidays').insert({
            ...formData,
            added_by: user.id
        });

        if (error) {
            toast.error(error.message);
        } else {
            toast.success('Holiday added successfully');
            setIsModalOpen(false);
            setFormData({ date: '', reason: '' });
            fetchHolidays();
        }
    };

    const handleDelete = async (id) => {
        if (!confirm('Are you sure you want to remove this holiday?')) return;

        const { error } = await supabase.from('holidays').delete().eq('id', id);
        if (error) {
            toast.error('Failed to delete holiday');
        } else {
            toast.success('Holiday removed');
            fetchHolidays();
        }
    };

    const columns = [
        { 
            header: 'Date', 
            accessor: 'date',
            render: (row) => (
                <div className="flex items-center gap-2">
                    <Calendar className="h-4 w-4 text-indigo-500" />
                    <span className="font-medium text-slate-700">
                        {new Date(row.date).toLocaleDateString('en-IN', { 
                            weekday: 'short', 
                            day: 'numeric', 
                            month: 'long', 
                            year: 'numeric' 
                        })}
                    </span>
                </div>
            )
        },
        { header: 'Reason / Occasion', accessor: 'reason' },
        {
            header: 'Actions',
            accessor: 'id',
            render: (row) => (
                <Button 
                    variant="ghost" 
                    size="sm" 
                    className="text-red-500 hover:bg-red-50"
                    onClick={() => handleDelete(row.id)}
                >
                    <Trash2 className="h-4 w-4" />
                </Button>
            )
        }
    ];

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            <div className="flex justify-between items-center">
                <div>
                    <h2 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <PartyPopper className="h-6 w-6 text-indigo-600" />
                        Holidays Management
                    </h2>
                    <p className="text-sm text-slate-500">Add and manage official college holidays.</p>
                </div>
                <Button onClick={() => setIsModalOpen(true)}>
                    <Plus className="h-4 w-4 mr-2" />
                    Add Holiday
                </Button>
            </div>

            <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden">
                <Table 
                    columns={columns} 
                    data={holidays} 
                    loading={loading}
                    emptyMessage="No holidays scheduled yet." 
                />
            </div>

            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Add New Holiday">
                <form onSubmit={handleCreate} className="space-y-4">
                    <Input 
                        label="Date" 
                        type="date" 
                        value={formData.date} 
                        onChange={e => setFormData({...formData, date: e.target.value})} 
                        required 
                    />
                    <Input 
                        label="Reason / Occasion" 
                        value={formData.reason} 
                        onChange={e => setFormData({...formData, reason: e.target.value})} 
                        placeholder="e.g. Independence Day, Winter Break" 
                        required 
                    />
                    <div className="flex justify-end gap-2 pt-4">
                        <Button variant="ghost" type="button" onClick={() => setIsModalOpen(false)}>Cancel</Button>
                        <Button type="submit">Add Holiday</Button>
                    </div>
                </form>
            </Modal>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { Table } from '../../components/ui/Table';
import { Badge } from '../../components/ui/Badge';
import { toast } from '../../components/ui/Toast';
import { ConfirmModal } from '../../components/ui/ConfirmModal';
import { 
  CheckCircle2, XCircle, Clock, Calendar, 
  User, FileText, ChevronRight, Inbox 
} from 'lucide-react';

export const AdminLeaves = () => {
  const [leaves, setLeaves] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('pending');
  const [confirmAction, setConfirmAction] = useState(null); // { id, status, name }

  const fetchLeaves = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('leave_requests')
      .select('*, users!teacher_id(name, role, college_id)')
      .order('created_at', { ascending: false });

    if (error) toast.error('Failed to load leaves');
    else setLeaves(data || []);
    setLoading(false);
  };

  useEffect(() => {
    fetchLeaves();
  }, []);

  const handleUpdateStatus = async () => {
    if (!confirmAction) return;
    setLoading(true);
    try {
      const { error } = await supabase
        .from('leave_requests')
        .update({ status: confirmAction.status, approved_at: new Date().toISOString() })
        .eq('id', confirmAction.id);

      if (error) throw error;

      toast.success(`Leave request ${confirmAction.status} successfully`);
      setConfirmAction(null);
      fetchLeaves();
    } catch (err) {
      toast.error('Update failed');
    } finally {
      setLoading(false);
    }
  };

  const filteredLeaves = leaves.filter(l => {
    if (activeTab === 'pending') return l.status === 'pending';
    if (activeTab === 'approved') return l.status === 'approved';
    return l.status !== 'pending' && l.status !== 'approved'; // Rejections/Cancelled
  });

  const columns = [
    { 
      header: 'Faculty', 
      accessor: 'teacher_id',
      render: (row) => (
        <div className="flex flex-col">
          <span className="font-bold text-slate-900">{row.users?.name}</span>
          <span className="text-[10px] text-slate-400 font-extrabold uppercase tracking-tighter">{row.users?.college_id}</span>
        </div>
      )
    },
    { 
      header: 'Date', 
      accessor: 'date',
      render: (row) => (
        <div className="flex items-center gap-2 text-slate-600 font-medium">
          <Calendar className="h-3.5 w-3.5 text-slate-400" />
          {new Date(row.date).toLocaleDateString()}
        </div>
      )
    },
    { 
      header: 'Slots', 
      accessor: 'lecture_nos',
      render: (row) => (
        <div className="flex flex-wrap gap-1">
          {row.lecture_nos.split(',').map(s => (
            <Badge key={s} variant="outline" className="text-[9px] px-1.5 py-0 border-slate-200">L{s}</Badge>
          ))}
        </div>
      )
    },
    { 
      header: 'Reason', 
      accessor: 'reason',
      render: (row) => (
        <div className="max-w-[150px] truncate text-xs text-slate-500 italic" title={row.reason}>" {row.reason} "</div>
      )
    },
    {
      header: 'Actions',
      accessor: 'id',
      render: (row) => row.status === 'pending' && (
        <div className="flex items-center gap-1">
          <Button 
            variant="ghost" 
            size="sm" 
            className="text-green-600 hover:bg-green-50"
            onClick={() => setConfirmAction({ id: row.id, status: 'approved', name: row.users?.name })}
          >
            <CheckCircle2 className="h-4 w-4" />
          </Button>
          <Button 
            variant="ghost" 
            size="sm" 
            className="text-red-600 hover:bg-red-50"
            onClick={() => setConfirmAction({ id: row.id, status: 'rejected', name: row.users?.name })}
          >
            <XCircle className="h-4 w-4" />
          </Button>
        </div>
      )
    }
  ];

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Leave Approvals</h2>
          <p className="text-sm text-slate-500 font-medium">Manage and review faculty absence requests.</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 shadow-inner">
           {['pending', 'approved', 'history'].map(tab => (
             <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-5 py-2 text-[11px] font-extrabold uppercase tracking-widest rounded-lg transition-all ${activeTab === tab ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
             >
               {tab}
             </button>
           ))}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-3">
          <div className="panel overflow-hidden">
            <Table 
              columns={columns} 
              data={filteredLeaves} 
              loading={loading}
              emptyMessage={`No ${activeTab} leave requests found.`}
            />
          </div>
        </div>

        <div className="space-y-6">
           <div className="panel p-6 bg-indigo-50 border-indigo-100">
             <div className="w-10 h-10 rounded-xl bg-white flex items-center justify-center text-indigo-600 mb-4 shadow-sm border border-indigo-100">
                <Inbox className="h-5 w-5" />
             </div>
             <h3 className="font-bold text-indigo-900 mb-1">Queue Status</h3>
             <p className="text-xs text-indigo-700 font-medium mb-4">You have {leaves.filter(l => l.status === 'pending').length} requests awaiting your review.</p>
             <div className="space-y-2">
               <div className="flex justify-between text-[10px] font-bold uppercase tracking-tighter text-indigo-400">
                 <span>Resolution Rate</span>
                 <span>{Math.round((leaves.filter(l => l.status !== 'pending').length / (leaves.length || 1)) * 100)}%</span>
               </div>
               <div className="h-1.5 w-full bg-indigo-200 rounded-full overflow-hidden">
                 <div 
                  className="h-full bg-indigo-600 transition-all duration-1000" 
                  style={{ width: `${(leaves.filter(l => l.status !== 'pending').length / (leaves.length || 1)) * 100}%` }}
                />
               </div>
             </div>
           </div>

           <div className="panel p-6">
             <h3 className="text-xs font-extrabold text-slate-400 uppercase tracking-widest mb-4">Policy Reminder</h3>
             <ul className="space-y-3">
               {[
                 'Approvals trigger automated substitute alerts.',
                 'Rejected requests notify the faculty immediately.',
                 'Leaves are visible on the public timetable grid.'
               ].map((text, i) => (
                 <li key={i} className="flex gap-3 text-[11px] text-slate-500 font-medium leading-relaxed">
                   <div className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 shrink-0" />
                   {text}
                 </li>
               ))}
             </ul>
           </div>
        </div>
      </div>

      <ConfirmModal
        isOpen={!!confirmAction}
        onClose={() => setConfirmAction(null)}
        onConfirm={handleUpdateStatus}
        title={`${confirmAction?.status === 'approved' ? 'Approve' : 'Reject'} Leave Request`}
        message={`Are you sure you want to ${confirmAction?.status} the leave request from ${confirmAction?.name}? This action cannot be undone.`}
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Table } from '../../components/ui/Table';
import { Badge } from '../../components/ui/Badge';
import { toast } from '../../components/ui/Toast';
import { parseExcel } from '../../lib/parseExcel';
import { parseCsv } from '../../lib/parseCsv';
import { useAuth } from '../../hooks/useAuth';
import { FileSpreadsheet, Upload, Download, CheckCircle, XCircle, AlertCircle } from 'lucide-react';
import * as XLSX from 'xlsx';

export const MarksUpload = () => {
  const { user } = useAuth();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState(null);

  // Selection Context
  const [selection, setSelection] = useState({
    branch: '',
    sem: '',
    subject_id: '',
    test_name: '',
    max_marks: ''
  });

  const [branches, setBranches] = useState([]);
  const [subjects, setSubjects] = useState([]);
  const [previewData, setPreviewData] = useState([]);
  const [results, setResults] = useState(null);
  const [history, setHistory] = useState([]);

  useEffect(() => {
    fetchInitialData();
  }, []);

  useEffect(() => {
    if (selection.branch && selection.sem) {
      fetchSubjects();
    }
  }, [selection.branch, selection.sem]);

  const fetchInitialData = async () => {
    const { data: bData } = await supabase.from('branches').select('*').order('name');
    if (bData) setBranches(bData);

    const { data: hData } = await supabase
      .from('bulk_upload_logs')
      .select('*, users:uploaded_by(name)')
      .eq('upload_type', 'marks')
      .order('created_at', { ascending: false });
    if (hData) setHistory(hData);
  };

  const fetchSubjects = async () => {
    const { data } = await supabase
      .from('subjects')
      .select('id, name, code')
      .eq('branch', selection.branch)
      .eq('sem', selection.sem)
      .order('name');
    if (data) setSubjects(data);
  };

  const handleFileSelect = async (e) => {
    const selected = e.target.files[0];
    if (!selected) return;

    setLoading(true);
    setFile(selected);

    try {
      let data = [];
      if (selected.name.endsWith('.csv')) data = await parseCsv(selected);
      else data = await parseExcel(selected);

      // Validate and enrich rows
      // Need student list for branch/sem
      const { data: students } = await supabase
        .from('students')
        .select('id, roll_no, users(name)')
        .eq('branch', selection.branch)
        .eq('sem', selection.sem);

      const enriched = data.map(row => {
        const student = students?.find(s => s.roll_no === row.roll_no);
        const errors = [];
        if (!student) errors.push('Roll No not found in this branch/sem');
        if (isNaN(row.marks)) errors.push('Marks must be numeric');
        if (parseFloat(row.marks) > parseFloat(selection.max_marks)) errors.push('Marks exceed Maximum');

        return {
          ...row,
          student_id: student?.id,
          student_name: student?.users?.name || 'Unknown',
          _isValid: errors.length === 0,
          _error: errors.join(', ')
        };
      });

      setPreviewData(enriched);
      setStep(3);
    } catch (err) {
      toast.error('Failed to parse file');
    } finally {
      setLoading(false);
    }
  };

  const handleImport = async () => {
    const validRows = previewData.filter(r => r._isValid);
    if (validRows.length === 0) return;

    setLoading(true);
    try {
      // 1. Determine table – if test_name contains 'CT', use ct_marks, else map correctly should be generic mark table
      // Spec says: "ct_marks" table is in schema.
      // Actually schema shows ct_marks for CT and endsem_marks for End Sem.
      const isCT = selection.test_name.toUpperCase().includes('CT');
      const tableName = isCT ? 'ct_marks' : 'ct_marks'; // Using mapping as per schema

      const { data: yearConfig } = await supabase.from('system_config').select('value').eq('key', 'academic_year').single();
      const academic_year = yearConfig?.value || '2024-25';

      const insertData = validRows.map(row => ({
        student_id: row.student_id,
        subject_id: selection.subject_id,
        test_name: selection.test_name,
        marks_obtained: parseFloat(row.marks),
        max_marks: parseFloat(selection.max_marks),
        academic_year
      }));

      const { error } = await supabase.from(tableName).upsert(insertData, { onConflict: 'student_id,subject_id,test_name' });

      if (error) throw error;

      await supabase.from('bulk_upload_logs').insert({
        file_name: file.name,
        upload_type: 'marks',
        status: 'completed',
        uploaded_by: user.id
      });

      setResults({ success: validRows.length, failed: previewData.length - validRows.length });
      setStep(4);
      fetchInitialData();
      toast.success('Marks uploaded successfully');
    } catch (err) {
      toast.error(err.message || 'Import failed');
    } finally {
      setLoading(false);
    }
  };

  const downloadTemplate = () => {
    const headers = [['roll_no', 'marks']];
    const ws = XLSX.utils.aoa_to_sheet(headers);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'MarksTemplate');
    XLSX.writeFile(wb, 'marks_upload_template.xlsx');
  };

  const reset = () => {
    setStep(1);
    setFile(null);
    setPreviewData([]);
    setResults(null);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-900 leading-tight">Academic Marks Upload</h2>
          <p className="text-sm text-slate-500">Upload internal assessment or custom test marks.</p>
        </div>
        <Button variant="ghost" size="sm" onClick={downloadTemplate}>
          <Download className="h-4 w-4 mr-2" />
          Download Template
        </Button>
      </div>

      <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden">
        {/* Step Indicators */}
        <div className="flex border-b border-slate-100">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className={`flex-1 flex items-center justify-center py-3 text-xs font-bold gap-2 ${step === i ? 'bg-indigo-50 text-indigo-600 border-b-2 border-indigo-600' : 'text-slate-400'}`}>
              <div className={`w-5 h-5 rounded-full flex items-center justify-center border-2 ${step === i ? 'border-indigo-600' : 'border-slate-300'}`}>{i}</div>
              {i === 1 ? 'CONTEXT' : i === 2 ? 'FILE' : i === 3 ? 'PREVIEW' : 'RESULT'}
            </div>
          ))}
        </div>

        <div className="p-8">
          {step === 1 && (
            <div className="space-y-6 max-w-2xl mx-auto">
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium">Branch</label>
                  <select 
                    className="w-full h-10 px-3 border border-slate-300 rounded focus:ring-2 focus:ring-indigo-600 outline-none bg-white"
                    value={selection.branch}
                    onChange={e => setSelection({...selection, branch: e.target.value})}
                  >
                    <option value="">Select Branch...</option>
                    {branches.map(b => <option key={b.id} value={b.name}>{b.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-medium">Semester</label>
                  <select 
                    className="w-full h-10 px-3 border border-slate-300 rounded focus:ring-2 focus:ring-indigo-600 outline-none bg-white"
                    value={selection.sem}
                    onChange={e => setSelection({...selection, sem: e.target.value})}
                  >
                    <option value="">Select Sem...</option>
                    {[1,2,3,4,5,6,7,8].map(s => <option key={s} value={s.toString()}>{s}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1.5">
                  <label className="text-sm font-medium">Subject</label>
                  <select 
                     className="w-full h-10 px-3 border border-slate-300 rounded focus:ring-2 focus:ring-indigo-600 outline-none bg-white"
                     value={selection.subject_id}
                     onChange={e => setSelection({...selection, subject_id: e.target.value})}
                     disabled={!selection.branch || !selection.sem}
                  >
                    <option value="">Select Subject...</option>
                    {subjects.map(s => <option key={s.id} value={s.id}>{s.code} - {s.name}</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-2 gap-3">
                   <Input 
                      label="Test Name" 
