import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Table } from '../../components/ui/Table';
import { Modal } from '../../components/ui/Modal';
import { ConfirmModal } from '../../components/ui/ConfirmModal';
import { toast } from '../../components/ui/Toast';
import { SystemSettingsForm } from '../../components/ui/SystemSettingsForm';
import { Settings, Plus, Trash2, AlertTriangle, RefreshCw } from 'lucide-react';

export const AdminPreferences = () => {
  const [branches, setBranches] = useState([]);
  const [loading, setLoading] = useState(true);
  const [newBranch, setNewBranch] = useState('');
  const [branchModalOpen, setBranchModalOpen] = useState(false);
  const [resetModalOpen, setResetModalOpen] = useState(false);
  const [confirmText, setConfirmText] = useState('');
  const [branchToDelete, setBranchToDelete] = useState(null);

  useEffect(() => {
    fetchBranches();
  }, []);

  async function fetchBranches() {
    setLoading(true);
    const { data } = await supabase.from('branches').select('*').order('name');
    if (data) setBranches(data);
    setLoading(false);
  }

  const handleAddBranch = async (e) => {
    e.preventDefault();
    if (!newBranch.trim()) return;
    const { error } = await supabase.from('branches').insert({ name: newBranch.trim().toUpperCase() });
    if (error) toast.error('Branch already exists');
    else {
      toast.success('Branch added');
      setNewBranch('');
      setBranchModalOpen(false);
      fetchBranches();
    }
  };

  const handleDeleteBranch = async () => {
    const { error } = await supabase.from('branches').delete().eq('id', branchToDelete.id);
    if (error) toast.error('Cannot delete branch with active records');
    else {
      toast.success('Branch deleted');
      fetchBranches();
    }
    setBranchToDelete(null);
  };

  const handleResetDefaults = async () => {
    if (confirmText !== 'RESET') return toast.error('Type RESET to confirm');
    const { error } = await supabase.from('system_config').upsert([
      { key: 'lectures_per_day', value: '8' },
      { key: 'working_days_per_week', value: '6' }
    ]);
    if (error) toast.error('Reset failed');
    else {
      toast.success('System reset to defaults');
      window.location.reload();
    }
  };

  return (
    <div className="space-y-8 max-w-4xl animate-in fade-in duration-500">
      <div>
        <h2 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
          <Settings className="h-6 w-6 text-indigo-600" />
          System Preferences
        </h2>
        <p className="text-sm text-slate-500">Configure global settings and manage organizational structure.</p>
      </div>

      <SystemSettingsForm />

      <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
          <h3 className="font-semibold text-slate-800">Branch Management</h3>
          <Button size="sm" onClick={() => setBranchModalOpen(true)}>
            <Plus className="h-4 w-4 mr-1" /> Add Branch
          </Button>
        </div>
        <div className="p-6">
          <Table 
            columns={[
              { header: 'Branch Name', accessor: 'name' },
              { header: 'Created At', accessor: 'created_at', render: (row) => new Date(row.created_at).toLocaleDateString() },
              { header: 'Actions', accessor: 'id', render: (row) => (
                <Button variant="ghost" size="sm" className="text-red-600" onClick={() => setBranchToDelete(row)}><Trash2 className="h-4 w-4" /></Button>
              )}
            ]} 
            data={branches} 
          />
        </div>
      </div>

      <div className="p-6 bg-white rounded-lg border-2 border-red-50 space-y-4">
        <div className="flex items-center gap-2 text-red-600 font-bold text-xs uppercase"><AlertTriangle className="h-4 w-4" /> Danger Zone</div>
        <div className="flex justify-between items-center">
          <div><p className="font-semibold text-slate-800">Reset System Config</p><p className="text-xs text-slate-500">Factory reset lecture counts and working days.</p></div>
          <Button variant="danger" onClick={() => setResetModalOpen(true)}>Reset Defaults</Button>
        </div>
      </div>

      <Modal isOpen={branchModalOpen} onClose={() => setBranchModalOpen(false)} title="Add Branch">
        <form onSubmit={handleAddBranch} className="space-y-4">
          <Input label="Branch Name" value={newBranch} onChange={e => setNewBranch(e.target.value)} required />
          <Button type="submit" className="w-full">Create Branch</Button>
        </form>
      </Modal>

      <ConfirmModal isOpen={!!branchToDelete} onClose={() => setBranchToDelete(null)} onConfirm={handleDeleteBranch} title="Delete Branch" message="This action is permanent." />

      <Modal isOpen={resetModalOpen} onClose={() => setResetModalOpen(false)} title="Reset System">
        <div className="space-y-4">
          <p className="text-sm">Type <span className="font-bold underline">RESET</span> to confirm:</p>
          <Input value={confirmText} onChange={e => setConfirmText(e.target.value)} placeholder="RESET" />
          <Button variant="danger" className="w-full" onClick={handleResetDefaults}>Execute Reset</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { Table } from '../../components/ui/Table';
import { Badge } from '../../components/ui/Badge';
import { toast } from '../../components/ui/Toast';
import { ConfirmModal } from '../../components/ui/ConfirmModal';
import { useAuth } from '../../hooks/useAuth';
import { 
  ArrowRight, AlertTriangle, History, GraduationCap, 
  Info, Sparkles, UserCheck, ShieldAlert, 
  RefreshCw, ChevronRight, Landmark, ArrowLeftRight
} from 'lucide-react';

export const SemTransition = () => {
  const { user } = useAuth();
  const [branches, setBranches] = useState([]);
  const [selectedBranch, setSelectedBranch] = useState('');
  const [currentSem, setCurrentSem] = useState('1');
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState([]);
  const [isConfirmOpen, setIsConfirmOpen] = useState(false);
  const [direction, setDirection] = useState('increase'); // Spec A7: Increase or Decrease

  useEffect(() => {
    fetchInitialData();
  }, []);

  const fetchInitialData = async () => {
    const { data: bData } = await supabase.from('branches').select('*').order('name');
    if (bData) {
        setBranches(bData);
        if (bData.length > 0) setSelectedBranch(bData[0].name);
    }

    const { data: hData } = await supabase
      .from('semester_transitions')
      .select('*, users:triggered_by(name)')
      .order('created_at', { ascending: false });
    if (hData) setHistory(hData);
  };

  const handleFetchStudents = async () => {
    if (!selectedBranch) return toast.error('Please select a branch');
    setLoading(true);
    try {
        const { data } = await supabase
          .from('students')
          .select('id, roll_no, users(name)')
          .eq('branch', selectedBranch)
          .eq('sem', parseInt(currentSem))
          .order('roll_no');

        if (data) setStudents(data);
        if (data?.length === 0) toast.info('No students found for this selection');
    } catch (err) {
        toast.error('Search failed');
    } finally {
        setLoading(false);
    }
  };

  const executeTransition = async () => {
    const nextSem = direction === 'increase' ? parseInt(currentSem) + 1 : parseInt(currentSem) - 1;

    if (nextSem > 8) {
       toast.error('Maximum academic maturity reached (SEM 8)');
       return;
    }
    if (nextSem < 1) {
       toast.error('Minimum academic level reached (SEM 1)');
       return;
    }

    setLoading(true);
    try {
      const studentIds = students.map(s => s.id);

      const { error: updateError } = await supabase
        .from('students')
        .update({ sem: nextSem })
        .in('id', studentIds);

      if (updateError) throw updateError;

      await supabase.from('semester_transitions').insert({
        branch: selectedBranch,
        old_sem: parseInt(currentSem),
        new_sem: nextSem,
        affected_students: students.length,
        triggered_by: user.id
      });

      toast.success(`Advancement Complete: ${students.length} students processed.`);
      setStudents([]);
      fetchInitialData();
    } catch (err) {
      toast.error(err.message || 'Transition failed');
    } finally {
      setLoading(false);
      setIsConfirmOpen(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <div className="flex items-center gap-2 text-indigo-600 mb-1">
             <Sparkles className="h-4 w-4" />
             <span className="text-[10px] font-extrabold uppercase tracking-[0.2em]">Academic Advancement</span>
          </div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Semester Transition</h2>
          <p className="text-sm text-slate-500 font-medium">Batch process student promotion and academic cycle resets.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-1 space-y-6">
           <div className="panel p-6 bg-white border-slate-200 shadow-xl shadow-slate-100/50">
              <h3 className="text-xs font-extrabold text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2">
                <Landmark className="h-4 w-4" />
                Transition Scope
              </h3>
              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-700 uppercase tracking-wider">Source Branch</label>
                  <select 
                    className="w-full h-11 px-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-slate-700 text-sm focus:ring-2 focus:ring-indigo-600 appearance-none"
                    value={selectedBranch}
                    onChange={e => setSelectedBranch(e.target.value)}
                  >
                    {branches.map(b => <option key={b.id} value={b.name}>{b.name.toUpperCase()}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-700 uppercase tracking-wider">Current State (SEM)</label>
                  <div className="grid grid-cols-4 gap-2">
                    {[1, 2, 3, 4, 5, 6, 7, 8].map(s => (
                       <button
                        key={s}
                        type="button"
                        onClick={() => setCurrentSem(s.toString())}
                        className={`h-11 rounded-xl text-xs font-bold transition-all border ${currentSem === s.toString() ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-400 border-slate-200 hover:border-indigo-400'}`}
                       >
                         {s}
                       </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-700 uppercase tracking-wider">Operation Mode</label>
                  <div className="flex gap-2">
                    <button 
                        onClick={() => setDirection('increase')}
                        className={`flex-1 h-10 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all border ${direction === 'increase' ? 'bg-indigo-50 border-indigo-200 text-indigo-600' : 'bg-white border-slate-200 text-slate-400'}`}
                    >
                        Increase
                    </button>
                    <button 
                        onClick={() => setDirection('decrease')}
                        className={`flex-1 h-10 rounded-xl text-[10px] font-black uppercase tracking-wider transition-all border ${direction === 'decrease' ? 'bg-red-50 border-red-200 text-red-600' : 'bg-white border-slate-200 text-slate-400'}`}
                    >
                        Decrease
                    </button>
                  </div>
                </div>

                <Button className="w-full h-11 rounded-xl shadow-lg shadow-indigo-100" onClick={handleFetchStudents} disabled={loading}>
                  {loading ? <RefreshCw className="h-4 w-4 animate-spin mr-2" /> : <UserCheck className="h-4 w-4 mr-2" />}
                  Identify Candidates
                </Button>
              </div>
           </div>

           <div className="panel p-6 bg-orange-50 border-orange-100">
              <div className="flex items-center gap-2 text-orange-600 font-bold text-[10px] uppercase tracking-widest mb-3">
                <ShieldAlert className="h-4 w-4" />
                Critical Protocol
              </div>
              <p className="text-[11px] text-orange-800 leading-relaxed font-medium">
                Changing student levels is a database-wide atomic operation. Ensure all records for the current term are safely archived before commit.
              </p>
           </div>
        </div>

        <div className="lg:col-span-3 space-y-6">
           {students.length > 0 ? (
             <div className="panel p-0 overflow-hidden border-slate-200 shadow-xl shadow-slate-100/50 bg-white animate-in slide-in-from-right-10 duration-500">
                <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row md:items-center justify-between gap-4">
                   <div className="flex items-center gap-4">
                     <div className="w-12 h-12 rounded-2xl bg-slate-100 text-slate-500 flex items-center justify-center shadow-sm font-black text-xs">
                        {currentSem}
                     </div>
                     <ArrowRight className={`h-5 w-5 ${direction === 'increase' ? 'text-indigo-600' : 'text-red-500 rotate-180'}`} />
                     <div className={`w-12 h-12 rounded-2xl text-white flex items-center justify-center shadow-lg font-black text-xs ${direction === 'increase' ? 'bg-indigo-600 shadow-indigo-100' : 'bg-red-500 shadow-red-100'}`}>
                        {direction === 'increase' ? parseInt(currentSem)+1 : parseInt(currentSem)-1}
                     </div>
                     <div className="ml-4">
                        <h4 className="font-bold text-slate-900 tracking-tight">{direction === 'increase' ? 'Promoting' : 'Regressing'} {students.length} Students</h4>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{selectedBranch} Cohort</p>
                     </div>
                   </div>
                   <Button variant={direction === 'increase' ? 'indigo' : 'danger'} onClick={() => setIsConfirmOpen(true)} className="px-8 h-12 rounded-2xl shadow-lg">
                      Commit Operation
                   </Button>
                </div>

                <div className="max-h-[500px] overflow-auto">
                   <Table 
                    columns={[
                        { header: 'Student Registry', accessor: 'users', render: r => (
                            <div className="flex items-center gap-3">
                                <div className="w-8 h-8 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-400 uppercase">
                                    {r.users?.name?.charAt(0)}
                                </div>
                                <div className="flex flex-col">
                                    <span className="font-bold text-slate-800">{r.users?.name}</span>
                                    <span className="text-[9px] text-slate-400 font-extrabold uppercase tracking-widest">{r.roll_no}</span>
                                </div>
                            </div>
                        )},
                        { header: 'Current Stage', accessor: 'id', render: () => <Badge variant="slate" className="uppercase text-[9px]">Semester {currentSem}</Badge> },
                        { header: 'Target State', accessor: 'id', render: () => <Badge variant={direction === 'increase' ? 'indigo' : 'danger'} className="uppercase text-[9px]">Semester {direction === 'increase' ? parseInt(currentSem)+1 : parseInt(currentSem)-1}</Badge> },
                    ]}
                    data={students}
                   />
                </div>
             </div>
           ) : (
             <div className="panel h-[400px] flex flex-col items-center justify-center border-slate-200 border-dashed bg-slate-50/50 text-slate-400">
                <div className="p-6 bg-white rounded-3xl shadow-sm mb-4 border border-slate-100">
                   <GraduationCap className="h-10 w-10 opacity-20" />
                </div>
                <p className="text-sm font-bold tracking-tight text-slate-900 border-b border-white pb-2 mb-2">Ready to Pipeline</p>
                <p className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Identify candidates to start the transition</p>
             </div>
           )}

           <div className="space-y-4">
            <h3 className="text-xs font-extrabold text-slate-400 uppercase tracking-widest flex items-center gap-2 pl-2">
               <History className="h-4 w-4" />
               Historical Registry
            </h3>
            <div className="panel p-0 overflow-hidden border-slate-200 shadow-xl shadow-slate-100/30 bg-white">
                <Table 
                columns={[
                    { header: 'Department', accessor: 'branch', render: r => <span className="font-black text-slate-700 text-xs">{r.branch.toUpperCase()}</span> },
                    { header: 'Progression', accessor: 'id', render: (row) => (
                        <div className="flex items-center gap-2 text-xs font-bold">
                            <span className="text-slate-400">SEM {row.old_sem}</span>
                            <ChevronRight className={`h-3 w-3 ${row.new_sem > row.old_sem ? 'text-indigo-300' : 'text-red-300'}`} />
                            <span className={row.new_sem > row.old_sem ? 'text-indigo-600' : 'text-red-500'}>SEM {row.new_sem}</span>
                        </div>
                    )},
                    { header: 'Batch Size', accessor: 'affected_students', render: r => <span className="text-xs font-medium text-slate-500">{r.affected_students} Users</span> },
                    { header: 'Audit', accessor: 'users', render: (row) => <span className="text-[11px] font-medium text-slate-600">{row.users?.name || 'System'}</span> },
                    { header: 'Timestamp', accessor: 'created_at', render: (row) => <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(row.created_at).toLocaleString('en-IN')}</span> }
                ]} 
                data={history} 
                emptyMessage="No historical progressions recorded."
                />
            </div>
           </div>
        </div>
      </div>

      <ConfirmModal 
        isOpen={isConfirmOpen}
        onClose={() => setIsConfirmOpen(false)}
        onConfirm={executeTransition}
        title={direction === 'increase' ? 'Commit Academic Advancement?' : 'Commit Academic Regression?'}
        message={`This will move ${students.length} students from the ${selectedBranch} cohort into Semester ${direction === 'increase' ? parseInt(currentSem)+1 : parseInt(currentSem)-1}. This is recorded in the audit registry.`}
        variant={direction === 'increase' ? 'indigo' : 'danger'}
        confirmText="Confirm Operation"
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Table } from '../../components/ui/Table';
import { Modal } from '../../components/ui/Modal';
import { Badge } from '../../components/ui/Badge';
import { toast } from '../../components/ui/Toast';
import { useAuth } from '../../hooks/useAuth';
import { 
  BookOpen, Search, Filter, UserCog, 
  Plus, Trash2, BookText, GraduationCap, 
  ChevronRight, Library, MoreVertical, 
  UserPlus, Link as LinkIcon 
} from 'lucide-react';

export const AdminSubjects = () => {
  const { user } = useAuth();
  const [subjects, setSubjects] = useState([]);
  const [branches, setBranches] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [loading, setLoading] = useState(true);

  const [search, setSearch] = useState('');
  const [branchFilter, setBranchFilter] = useState('All');
  const [semFilter, setSemFilter] = useState('All');

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);
  const [selectedSubject, setSelectedSubject] = useState(null);

  const [formData, setFormData] = useState({
    name: '',
    code: '',
    credits: 4,
    type: 'theory',
    branch: '',
    sem: '1'
  });

  const [assignmentData, setAssignmentData] = useState({
    teacher_id: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    const [branchesRes, subjectsRes, assignmentsRes, teachersRes] = await Promise.all([
      supabase.from('branches').select('*').order('name'),
      supabase.from('subjects').select('*').order('code'),
      supabase.from('subject_assignments').select('*, users:teacher_id(name)'),
      supabase.from('users').select('id, name, college_id').eq('role', 'teacher').eq('is_active', true)
    ]);

    if (branchesRes.data) {
        setBranches(branchesRes.data);
        if (branchesRes.data.length > 0 && !formData.branch) {
            setFormData(prev => ({ ...prev, branch: branchesRes.data[0].name }));
        }
    }
    if (teachersRes.data) setTeachers(teachersRes.data);

    if (subjectsRes.data) {
      const enriched = subjectsRes.data.map(sub => {
        const assignment = assignmentsRes.data?.find(a => a.subject_id === sub.id);
        return {
          ...sub,
          teacher_name: assignment?.users?.name || 'Unassigned',
          teacher_id: assignment?.teacher_id || null
        };
      });
      setSubjects(enriched);
    }
    setLoading(false);
  };

  const handleAddSubject = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { error } = await supabase.from('subjects').insert({
        ...formData,
        sem: parseInt(formData.sem)
      });

      if (error) throw error;
      toast.success(`${formData.code} created successfully`);
      setIsAddModalOpen(false);
      setFormData({ name: '', code: '', credits: 4, type: 'theory', branch: branches[0]?.name || '', sem: '1' });
      fetchData();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleAssignTeacher = async (e) => {
    e.preventDefault();
    if (!assignmentData.teacher_id) {
       toast.error('Select a teacher');
       return;
    }

    const { data: config } = await supabase.from('system_config').select('value').eq('key', 'academic_year').single();

    const { error } = await supabase.from('subject_assignments').upsert({
      subject_id: selectedSubject.id,
      teacher_id: assignmentData.teacher_id,
      academic_year: config?.value || '2024-25'
    }, { onConflict: 'subject_id,academic_year' });

    if (error) toast.error(error.message);
    else {
      toast.success('Teacher linked to subject');
      setIsAssignModalOpen(false);
      fetchData();
    }
  };

  const handleDeleteSubject = async (subject) => {
    if (!confirm(`Permanently delete ${subject.code}?`)) return;
    const { error } = await supabase.from('subjects').delete().eq('id', subject.id);
    if (error) toast.error('Failed: ' + error.message);
    else {
      toast.success('Subject removed');
      fetchData();
    }
  };

  const filteredSubjects = subjects.filter(s => {
    const matchesSearch = s.name.toLowerCase().includes(search.toLowerCase()) || 
                         s.code.toLowerCase().includes(search.toLowerCase());
    const matchesBranch = branchFilter === 'All' || s.branch === branchFilter;
    const matchesSem = semFilter === 'All' || s.sem.toString() === semFilter;
    return matchesSearch && matchesBranch && matchesSem;
  });

  const columns = [
    { 
      header: 'Subject Code', 
      accessor: 'code', 
      render: (row) => (
        <div className="flex flex-col">
          <span className="font-black text-indigo-600 tracking-widest text-xs">{row.code.toUpperCase()}</span>
          <span className="text-[9px] text-slate-400 font-extrabold uppercase tracking-tighter">Credits: {row.credits}</span>
        </div>
      )
    },
    { 
      header: 'Course Information', 
      accessor: 'name',
      render: (row) => (
        <div className="flex flex-col max-w-[200px]">
          <span className="font-bold text-slate-800 line-clamp-1">{row.name}</span>
          <div className="flex gap-2 items-center">
            <Badge variant="outline" className="text-[8px] px-1 py-0 border-slate-200">{row.type.toUpperCase()}</Badge>
            <span className="text-[10px] text-slate-400 font-bold uppercase">{row.branch} • SEM {row.sem}</span>
          </div>
        </div>
      )
    },
    { 
      header: 'Assigned Faculty', 
      accessor: 'teacher_name',
      render: (row) => (
        <div className="flex items-center gap-3">
          <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-[10px] font-black border transition-all ${row.teacher_name === 'Unassigned' ? 'bg-red-50 text-red-400 border-red-100' : 'bg-indigo-50 text-indigo-600 border-indigo-100'}`}>
            {row.teacher_name === 'Unassigned' ? '?' : row.teacher_name.charAt(0)}
          </div>
          <div className="flex flex-col">
            <span className={`text-xs font-bold ${row.teacher_name === 'Unassigned' ? 'text-red-400 italic' : 'text-slate-700'}`}>
              {row.teacher_name}
            </span>
            {row.teacher_name !== 'Unassigned' && <span className="text-[9px] text-slate-400 font-bold uppercase">Primary Faculty</span>}
          </div>
        </div>
      )
    },
    {
      header: 'Operations',
      accessor: 'id',
      render: (row) => (
        <div className="flex items-center gap-1">
           <Button variant="ghost" size="sm" className="text-indigo-600 hover:bg-indigo-50 rounded-lg" onClick={() => { setSelectedSubject(row); setAssignmentData({ teacher_id: row.teacher_id || '' }); setIsAssignModalOpen(true); }}>
             <UserCog className="h-4 w-4" />
           </Button>
           <Button variant="ghost" size="sm" className="text-red-400 hover:bg-red-50 hover:text-red-600 rounded-lg" onClick={() => handleDeleteSubject(row)}>
             <Trash2 className="h-4 w-4" />
           </Button>
        </div>
      )
    }
  ];

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <div className="flex items-center gap-2 text-indigo-600 mb-1">
             <Library className="h-4 w-4" />
             <span className="text-[10px] font-extrabold uppercase tracking-[0.2em]">Curriculum Management</span>
          </div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Academic Courses</h2>
          <p className="text-sm text-slate-500 font-medium">Manage subject database and faculty linkings.</p>
        </div>
        <Button onClick={() => setIsAddModalOpen(true)} className="px-8 shadow-lg shadow-indigo-100">
          <Plus className="h-4 w-4 mr-2" />
          Add Course
        </Button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-1 space-y-6">
           <div className="panel p-6 bg-slate-900 text-white border-none overflow-hidden relative group">
              <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-110 transition-transform">
                <GraduationCap className="h-24 w-24" />
              </div>
              <h3 className="font-bold text-lg mb-6 flex items-center gap-2">
                <BookText className="h-5 w-5 text-indigo-400" />
                Integration Rules
              </h3>
              <ul className="space-y-4 relative z-10">
                <li className="flex gap-3 text-xs font-medium text-slate-400">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 mt-1.5 shrink-0" />
                  Course codes must align with state university guidelines.
                </li>
                <li className="flex gap-3 text-xs font-medium text-slate-400">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 mt-1.5 shrink-0" />
                  Each course must have exactly one primary faculty for analytics.
                </li>
                <li className="flex gap-3 text-xs font-medium text-slate-400">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 mt-1.5 shrink-0" />
                  Lab courses automatically trigger separate marking schemes.
                </li>
              </ul>
           </div>

           <div className="panel p-6 border-slate-200">
              <h3 className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest mb-4">Quick Stats</h3>
              <div className="space-y-4">
                 <div>
                   <div className="flex justify-between text-xs font-bold mb-1.5">
                     <span className="text-slate-600">Faculty Coverage</span>
                     <span className="text-indigo-600">{subjects.length > 0 ? Math.round((subjects.filter(s=>s.teacher_name !== 'Unassigned').length / subjects.length) * 100) : 0}%</span>
                   </div>
                   <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                     <div className="h-full bg-indigo-600" style={{ width: `${subjects.length > 0 ? (subjects.filter(s=>s.teacher_name !== 'Unassigned').length / subjects.length) * 100 : 0}%` }} />
                   </div>
                 </div>
                 <div className="flex items-center gap-3 pt-2">
                   <div className="p-2 bg-indigo-50 rounded-lg text-indigo-600 shadow-sm">
                     <BookOpen className="h-4 w-4" />
                   </div>
                   <div>
                     <p className="text-[10px] font-extrabold text-slate-400 uppercase">Total Load</p>
                     <p className="text-sm font-black text-slate-700">{subjects.length} Courses</p>
                   </div>
                 </div>
              </div>
           </div>
        </div>

        <div className="lg:col-span-3 space-y-4">
           <div className="panel p-0 overflow-hidden border-slate-200 shadow-xl shadow-slate-100/50 bg-white">
              <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row md:items-center gap-4">
                <div className="relative flex-1">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
                  <input 
                    type="text"
                    className="w-full h-11 pl-11 pr-4 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-600/20 text-sm font-medium"
                    placeholder="Search curriculum database..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                  />
                </div>
                <div className="flex gap-2">
                  <select className="h-11 px-4 bg-white border border-slate-200 rounded-xl text-xs font-bold outline-none cursor-pointer focus:ring-2 focus:ring-indigo-600/10" value={branchFilter} onChange={e => setBranchFilter(e.target.value)}>
                    <option>All Branches</option>
                    {branches.map(b => <option key={b.id} value={b.name}>{b.name.toUpperCase()}</option>)}
                  </select>
                  <select className="h-11 px-4 bg-white border border-slate-200 rounded-xl text-xs font-bold outline-none cursor-pointer focus:ring-2 focus:ring-indigo-600/10" value={semFilter} onChange={e => setSemFilter(e.target.value)}>
                    <option value="All">All Sems</option>
                    {[1,2,3,4,5,6,7,8].map(s => <option key={s} value={s.toString()}>SEM {s}</option>)}
                  </select>
                </div>
              </div>

              <Table columns={columns} data={filteredSubjects} loading={loading} emptyMessage="No subjects found in the current archive." />
           </div>
        </div>
      </div>

      {/* Add Course Modal */}
      <Modal isOpen={isAddModalOpen} onClose={() => setIsAddModalOpen(false)} title="Register Academic Course">
        <form onSubmit={handleAddSubject} className="space-y-6">
          <div className="grid grid-cols-2 gap-4">
             <Input label="Course Code" value={formData.code} onChange={e => setFormData({...formData, code: e.target.value.toUpperCase()})} placeholder="e.g. CS501" required />
             <Input label="Course Title" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="e.g. Artificial Intelligence" required />
          </div>

          <div className="grid grid-cols-3 gap-4">
             <div className="space-y-2">
               <label className="text-xs font-bold text-slate-700 uppercase tracking-wider">Branch</label>
               <select className="w-full h-11 px-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm" value={formData.branch} onChange={e => setFormData({...formData, branch: e.target.value})} required>
                 {branches.map(b => <option key={b.id} value={b.name}>{b.name}</option>)}
               </select>
             </div>
             <div className="space-y-2">
               <label className="text-xs font-bold text-slate-700 uppercase tracking-wider">Semester</label>
               <select className="w-full h-11 px-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm" value={formData.sem} onChange={e => setFormData({...formData, sem: e.target.value})} required>
                 {[1,2,3,4,5,6,7,8].map(s => <option key={s} value={s.toString()}>{s}</option>)}
               </select>
             </div>
             <div className="space-y-2">
               <label className="text-xs font-bold text-slate-700 uppercase tracking-wider">Credits</label>
               <input type="number" min="1" max="5" className="w-full h-11 px-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm" value={formData.credits} onChange={e => setFormData({...formData, credits: parseInt(e.target.value)})} required />
             </div>
          </div>

          <div className="space-y-2">
             <label className="text-xs font-bold text-slate-700 uppercase tracking-wider">Course Taxonomy</label>
             <div className="grid grid-cols-3 gap-3">
               {['theory', 'lab', 'elective'].map(t => (
                 <button key={t} type="button" onClick={() => setFormData({...formData, type: t})} className={`h-11 rounded-xl border font-bold text-[10px] uppercase tracking-widest transition-all ${formData.type === t ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-100' : 'bg-white text-slate-400 border-slate-200 hover:border-indigo-400 hover:text-indigo-600'}`}>
                   {t}
                 </button>
               ))}
             </div>
          </div>

          <div className="flex justify-end gap-3 pt-6 border-t">
             <Button variant="ghost" type="button" onClick={() => setIsAddModalOpen(false)}>Discard</Button>
             <Button type="submit" disabled={loading} className="px-10 h-11 rounded-xl shadow-lg shadow-indigo-100">
               {loading ? <RefreshCw className="h-4 w-4 animate-spin" /> : 'Register Course'}
             </Button>
          </div>
        </form>
      </Modal>

      {/* Assign Teacher Modal */}
      <Modal isOpen={isAssignModalOpen} onClose={() => setIsAssignModalOpen(false)} title="Delegate Faculty Responsibilities">
        <form onSubmit={handleAssignTeacher} className="space-y-6">
          <div className="p-5 bg-indigo-50 border border-indigo-100 rounded-2xl flex items-center justify-between">
            <div className="flex items-center gap-3 text-indigo-700">
               <BookText className="h-5 w-5" />
               <div className="flex flex-col">
                  <span className="text-[10px] font-extrabold uppercase tracking-widest mb-0.5">Linking Policy</span>
                  <span className="text-sm font-bold tracking-tight">{selectedSubject?.code} — {selectedSubject?.name}</span>
               </div>
            </div>
            <LinkIcon className="h-4 w-4 text-indigo-300" />
          </div>

          <div className="space-y-2">
             <label className="text-xs font-bold text-slate-700 uppercase tracking-widest">Select Academic Professional</label>
             <select 
                className="w-full h-12 px-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-slate-700 text-sm focus:ring-2 focus:ring-indigo-600" 
                value={assignmentData.teacher_id} 
                onChange={e => setAssignmentData({ teacher_id: e.target.value })}
                required
              >
                <option value="">Choose Faculty Member...</option>
                {teachers.map(t => <option key={t.id} value={t.id}>{t.name} ({t.college_id})</option>)}
             </select>
          </div>

          <div className="p-4 bg-slate-50 border border-slate-200 rounded-xl text-[10px] text-slate-400 font-bold uppercase tracking-tight leading-relaxed">
             linking a faculty member will grant them permissions to mark attendance, manage session plans, and upload continuous assessment marks for this subject.
          </div>

          <div className="flex justify-end gap-3 pt-6 border-t">
             <Button variant="ghost" type="button" onClick={() => setIsAssignModalOpen(false)}>Cancel</Button>
             <Button type="submit" className="px-10 h-11 rounded-xl shadow-lg shadow-indigo-100">
                Establish Link
             </Button>
          </div>
        </form>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { Table } from '../../components/ui/Table';
import { Badge } from '../../components/ui/Badge';
import { Modal } from '../../components/ui/Modal';
import { ConfirmModal } from '../../components/ui/ConfirmModal';
import { toast } from '../../components/ui/Toast';
import { 
  Search, Filter, UserPlus, Download, Edit2, 
  Trash2, ShieldAlert, RefreshCw, Layers 
} from 'lucide-react';
import { exportCredentials } from '../../utils/exportExcel';
import { Link } from 'react-router-dom';

export const AdminUsers = () => {
  const [users, setUsers] = useState([]);
  const [branches, setBranches] = useState([]);
  const [loading, setLoading] = useState(true);

  // Filters
  const [search, setSearch] = useState('');
  const [roleFilter, setRoleFilter] = useState('All');
  const [branchFilter, setBranchFilter] = useState('All');
  const [semFilter, setSemFilter] = useState('All');

  // Modals
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [isConfirmOpen, setIsConfirmOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);

  // Form states (Editing only)
  const [formData, setFormData] = useState({
    name: '',
    role: 'student',
    roll_no: '',
    branch: '',
    sem: '1'
  });

  const fetchData = async () => {
    setLoading(true);
    const [branchesRes, usersRes, studentsRes] = await Promise.all([
      supabase.from('branches').select('*').order('name'),
      supabase.from('users').select('*').is('deleted_at', null).order('created_at', { ascending: false }),
      supabase.from('students').select('*')
    ]);

    if (branchesRes.data) setBranches(branchesRes.data);

    if (usersRes.data) {
      const enrichedUsers = usersRes.data.map(user => {
        const student = (studentsRes.data || []).find(s => s.user_id === user.id);
        return {
          ...user,
          roll_no: student?.roll_no || '',
          branch: student?.branch || '',
          sem: student?.sem || ''
        };
      });
      setUsers(enrichedUsers);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleUpdateUser = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { error: userError } = await supabase
        .from('users')
        .update({ name: formData.name, role: formData.role })
        .eq('id', selectedUser.id);

      if (userError) throw userError;

      if (formData.role === 'student') {
        const { error: studentError } = await supabase
          .from('students')
          .upsert({ 
            user_id: selectedUser.id,
            roll_no: formData.roll_no,
            branch: formData.branch,
            sem: parseInt(formData.sem)
          });
        if (studentError) throw studentError;
      }

      toast.success('User updated');
      setIsEditModalOpen(false);
      fetchData();
    } catch (err) {
      let msg = err.message || 'Update failed';
      if (msg.includes('students_roll_no_key')) {
        msg = 'Update Rejection: This Roll Number is already assigned to a different record.';
      } else if (msg.includes('users_college_id_key')) {
        msg = 'Update Rejection: This College ID is already registered.';
      }
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  };

  const syncRow = async (user) => {
    setLoading(true);
    try {
      const { error } = await supabase.rpc('sync_user_to_auth', { target_id: user.id });
      if (error) throw error;
      toast.success('Credentials synchronized!');
    } catch (err) {
      toast.error('Sync failed: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const confirmSoftDelete = async () => {
    if (!selectedUser) return;
    setLoading(true);
    try {
      const { error } = await supabase
        .from('users')
        .update({ is_active: false, deleted_at: new Date().toISOString() })
        .eq('id', selectedUser.id);

      if (error) throw error;
      toast.success(`Archived ${selectedUser.name}`);
      setIsConfirmOpen(false);
      fetchData();
    } catch (err) {
      toast.error('Archive failed');
    } finally {
      setLoading(false);
    }
  };

  const filteredUsers = users.filter(u => {
    const matchesSearch = u.name.toLowerCase().includes(search.toLowerCase()) || 
                         u.college_id.toLowerCase().includes(search.toLowerCase());
    const matchesRole = roleFilter === 'All' || u.role === roleFilter.toLowerCase();
    const matchesBranch = branchFilter === 'All' || u.branch === branchFilter;
    const matchesSem = semFilter === 'All' || String(u.sem ?? '') === semFilter;
    return matchesSearch && matchesRole && matchesBranch && matchesSem;
  });

  const columns = [
    { header: 'College ID', accessor: 'college_id', render: r => <span className="font-mono text-xs font-bold">{r.college_id}</span> },
    { header: 'Identity', accessor: 'name', render: r => <span className="font-bold text-slate-800">{r.name}</span> },
    { 
      header: 'Privilege', 
      accessor: 'role',
      render: (row) => (
        <Badge variant={row.role === 'admin' ? 'danger' : row.role === 'hod' ? 'purple' : 'default'} className="uppercase text-[9px]">
          {row.role}
        </Badge>
      )
    },
    { header: 'Academic Context', accessor: 'id', render: (row) => row.role === 'student' ? <span className="text-xs font-medium text-slate-500">{row.branch} (Roll: {row.roll_no})</span> : '—' },
    {
      header: 'Operations',
      accessor: 'id',
      render: (row) => (
        <div className="flex items-center gap-1">
          <Button variant="ghost" size="sm" onClick={() => {
            setSelectedUser(row);
            setFormData({
              name: row.name,
              role: row.role,
              roll_no: row.roll_no,
              branch: row.branch,
              sem: String(row.sem || '1')
            });
            setIsEditModalOpen(true);
          }}>
            <Edit2 className="h-4 w-4" />
          </Button>
          <Button variant="ghost" size="sm" className="text-indigo-600" onClick={() => syncRow(row)} title="Sync Auth">
            <RefreshCw className="h-4 w-4" />
          </Button>
          <Button variant="ghost" size="sm" className="text-amber-600" onClick={async () => {
              const newPass = prompt(`Enter new password for ${row.name}:`);
              if (newPass) {
                setLoading(true);
                try {
                  const { error } = await supabase.rpc('admin_reset_password', { 
                    target_id: row.id, 
                    new_password: newPass 
                  });
                  if (error) throw error;
                  toast.success('Password updated');
                } catch (err) {
                  toast.error('Update failed');
                } finally {
                  setLoading(false);
                }
              }
            }} title="Reset Password">
            <ShieldAlert className="h-4 w-4" />
          </Button>
          <Button variant="ghost" size="sm" className="text-red-600" onClick={() => {
            setSelectedUser(row);
            setIsConfirmOpen(true);
          }} title="Archive">
            <Trash2 className="h-4 w-4" />
          </Button>
        </div>
      )
    }
  ];

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <div className="flex items-center gap-2 text-indigo-600 mb-1">
             <Layers className="h-4 w-4" />
             <span className="text-[10px] font-extrabold uppercase tracking-[0.2em]">Institutional Matrix</span>
           </div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Active User Registry</h2>
          <p className="text-sm text-slate-500 font-medium">Monitoring and operational control for all system participants.</p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" onClick={() => exportCredentials(filteredUsers)}>
            <Download className="h-4 w-4 mr-2" />
            Registry Export (.xlsx)
          </Button>
          <Link to="/admin/bulk-upload">
            <Button className="shadow-lg shadow-indigo-100">
                <UserPlus className="h-4 w-4 mr-2" />
                Provision New Accounts
            </Button>
          </Link>
        </div>
      </div>

      <div className="p-4 bg-white rounded-2xl border border-slate-200 shadow-xl shadow-slate-100/50 flex flex-wrap items-center gap-4">
        <div className="relative flex-1 min-w-[300px]">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
          <input 
            type="text"
            className="w-full pl-12 pr-4 h-11 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600 transition-all font-bold text-slate-700"
            placeholder="Search by name, ID or role..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <div className="flex items-center gap-2">
          <Filter className="h-4 w-4 text-slate-400" />
          <select 
            className="bg-slate-50 h-11 border border-slate-200 rounded-xl text-xs py-2 px-4 focus:ring-indigo-600 font-black uppercase tracking-wider cursor-pointer outline-none"
            value={roleFilter}
            onChange={(e) => setRoleFilter(e.target.value)}
          >
            <option value="All">All Roles</option>
            <option>Admin</option>
            <option>HOD</option>
            <option>Teacher</option>
            <option>Student</option>
          </select>

          <select 
            className="bg-slate-50 h-11 border border-slate-200 rounded-xl text-xs py-2 px-4 focus:ring-indigo-600 font-black uppercase tracking-wider cursor-pointer outline-none"
            value={branchFilter}
            onChange={(e) => setBranchFilter(e.target.value)}
          >
            <option value="All">All Branches</option>
            {branches.map(b => <option key={b.id} value={b.name}>{b.name}</option>)}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-xl shadow-slate-200/50 overflow-hidden">
        <Table columns={columns} data={filteredUsers} emptyMessage="No active records found in registry." />
      </div>

      <Modal isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} title="Operational Override">
        <form onSubmit={handleUpdateUser} className="space-y-6">
          <div className="grid grid-cols-1 gap-6">
            <div className="space-y-1.5 flex flex-col">
                <label className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest pl-1">Legal Name</label>
                <input 
                    className="w-full h-11 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none"
                    value={formData.name} 
                    onChange={e => setFormData({...formData, name: e.target.value})} 
                    required 
                />
            </div>

            <div className="space-y-1.5 flex flex-col">
                <label className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest pl-1">Assigned Privilege</label>
                <select 
                    className="w-full h-11 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none cursor-pointer"
                    value={formData.role}
                    onChange={e => setFormData({...formData, role: e.target.value})}
                >
                    <option value="student">Student Account</option>
                    <option value="teacher">Faculty Account</option>
                    <option value="hod">HOD Account</option>
                    <option value="admin">System Admin</option>
                </select>
            </div>

            {formData.role === 'student' && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in slide-in-from-top-2">
                <div className="space-y-1.5 flex flex-col">
                  <label className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest pl-1">Academic Roll No</label>
                  <input 
                      className="w-full h-11 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none"
                      value={formData.roll_no} 
                      onChange={e => setFormData({...formData, roll_no: e.target.value})} 
                      required 
                  />
                </div>
                <div className="space-y-1.5 flex flex-col">
                  <label className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest pl-1">Current Semester</label>
                  <select 
                      className="w-full h-11 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none cursor-pointer"
                      value={formData.sem}
                      onChange={e => setFormData({...formData, sem: e.target.value})}
                  >
                      {[1,2,3,4,5,6,7,8].map(s => <option key={s} value={String(s)}>Semester {s}</option>)}
                  </select>
                </div>
                <div className="md:col-span-2 space-y-1.5 flex flex-col">
                  <label className="text-[10px] font-extrabold text-slate-400 uppercase tracking-widest pl-1">Branch/Department</label>
                  <select 
                      className="w-full h-11 px-4 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold outline-none cursor-pointer"
                      value={formData.branch}
                      onChange={e => setFormData({...formData, branch: e.target.value})}
                  >
                      {branches.map(b => <option key={b.id} value={b.name}>{b.name.toUpperCase()}</option>)}
                  </select>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-amber-50 rounded-2xl border border-amber-100 flex items-start gap-4">
            <ShieldAlert className="h-5 w-5 text-amber-500 shrink-0 mt-0.5" />
            <p className="text-[10px] text-amber-900 leading-relaxed font-bold uppercase tracking-tighter">
              AFFECTS PUBLIC IDENTITY ONLY. TO REPAIR CREDENTIALS OR RESET FORGOTTEN PASSWORDS, USE THE "SYNC AUTH" INSTRUMENT IN THE REGISTRY TABLE.
            </p>
          </div>

          <div className="flex justify-end gap-2 pt-6">
            <Button variant="ghost" type="button" onClick={() => setIsEditModalOpen(false)}>Cancel</Button>
            <Button type="submit" disabled={loading} className="px-10 h-11 rounded-xl shadow-lg shadow-indigo-100">
                {loading ? 'Processing...' : 'Commit Update'}
            </Button>
          </div>
        </form>
      </Modal>

      <ConfirmModal
        isOpen={isConfirmOpen}
        onClose={() => setIsConfirmOpen(false)}
        onConfirm={confirmSoftDelete}
        title="Sanitize Registry Record?"
        message={`Are you sure you want to archive ${selectedUser?.name}? Access will be revoked immediately. The record can be restored from the Recovery Terminal later.`}
        variant="danger"
      />
    </div>
  );
};

import React, { useState } from 'react';
import { Navigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { Input } from '../../components/ui/Input';
import { Button } from '../../components/ui/Button';
import { GraduationCap, ShieldCheck } from 'lucide-react';

export const Login = () => {
  const { session, role, login, loading: authLoading } = useAuth();
  const [collegeId, setCollegeId] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);

  // CRITICAL: prevents flash of login form
  if (authLoading) return null;
  if (session && role) return <Navigate to={`/${role}`} replace />;

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!collegeId || !password) return;
    setLoading(true);
    try {
      await login(collegeId, password);
    } catch (e) {
      // Error is handled in useAuth toast
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen w-full flex flex-col items-center justify-center bg-slate-50 px-4">
      <div className="mb-8 text-center animate-in fade-in slide-in-from-top duration-700">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-indigo-600 rounded-2xl shadow-xl shadow-indigo-100 mb-4">
          <GraduationCap className="h-10 w-10 text-white" />
        </div>
        <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">CAMS Portal</h1>
        <p className="text-slate-500 mt-2 font-medium">College Attendance Management System</p>
      </div>

      <div className="w-full max-w-md bg-white p-10 rounded-2xl shadow-2xl shadow-slate-200/50 border border-slate-100 animate-in fade-in slide-in-from-bottom duration-700">
        <form onSubmit={handleSubmit} className="space-y-6">
          <Input 
            label="College ID" 
            placeholder="e.g. 2024CS101"
            value={collegeId}
            onChange={(e) => setCollegeId(e.target.value)}
            disabled={loading}
            required
            className="h-12"
          />
          <Input 
            label="Password" 
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            disabled={loading}
            required
            className="h-12"
          />
          <Button 
            type="submit" 
            className="w-full h-12 text-base font-bold" 
            disabled={loading || !collegeId || !password}
          >
            {loading ? (
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                Signing in...
              </div>
            ) : 'Access Dashboard'}
          </Button>
        </form>
        
        <div className="mt-8 pt-6 border-t border-slate-100">
          <div className="flex items-start gap-3 bg-slate-50 p-4 rounded-lg">
            <ShieldCheck className="h-5 w-5 text-slate-400 shrink-0 mt-0.5" />
            <p className="text-xs text-slate-500 leading-relaxed">
              <strong>Security Protocol:</strong> Administrator creates all accounts. 
              Self-registration is disabled. Contact IT support if you cannot log in.
            </p>
          </div>
        </div>
      </div>
      
      <footer className="mt-12 text-slate-400 text-[10px] uppercase font-bold tracking-widest text-center">
        &copy; 2026 Educational Trust Management System &bull; V2.0 Production
      </footer>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { Button } from '../../components/ui/Button';
import { StatCard } from '../../components/ui/StatCard';
import { Table } from '../../components/ui/Table';
import { Badge } from '../../components/ui/Badge';
import { toast } from '../../components/ui/Toast';
import { 
  BarChart3, TrendingDown, TrendingUp, Filter, 
  Download, BookOpen, GraduationCap, ChevronRight 
} from 'lucide-react';

export const HodAnalysis = () => {
    const [branches, setBranches] = useState([]);
    const [subjects, setSubjects] = useState([]);
    const [filter, setFilter] = useState({ branch: '', sem: '', subject_id: '' });
    const [marksData, setMarksData] = useState([]);
    const [loading, setLoading] = useState(false);
    const [stats, setStats] = useState({ average: 0, highest: 0, lowest: 0, passing: 0 });

    useEffect(() => {
        const fetchBranches = async () => {
            const { data } = await supabase.from('branches').select('*').order('name');
            if (data) {
                setBranches(data);
                if (data.length > 0) setFilter(f => ({ ...f, branch: data[0].name, sem: '1' }));
            }
        };
        fetchBranches();
    }, []);

    useEffect(() => {
        if (filter.branch && filter.sem) {
            const fetchSubjects = async () => {
                const { data } = await supabase.from('subjects')
                    .select('id, name, code')
                    .eq('branch', filter.branch)
                    .eq('sem', parseInt(filter.sem));
                if (data) {
                    setSubjects(data);
                    if (data.length > 0) setFilter(f => ({ ...f, subject_id: data[0].id }));
                }
            };
            fetchSubjects();
        }
    }, [filter.branch, filter.sem]);

    const runAnalysis = async () => {
        if (!filter.subject_id) return;
        setLoading(true);
        try {
            const { data: marks } = await supabase.from('ct_marks')
                .select('*, students(roll_no, users(name))')
                .eq('subject_id', filter.subject_id);

            if (marks) {
                // Group by student
                const studentMap = {};
                marks.forEach(m => {
                    if (!studentMap[m.student_id]) {
                        studentMap[m.student_id] = {
                            name: m.students?.users?.name || 'Unknown',
                            roll_no: m.students?.roll_no || '—',
                            tests: {},
                            sum: 0,
                            count: 0
                        };
                    }
                    studentMap[m.student_id].tests[m.test_name] = m.marks_obtained;
                    studentMap[m.student_id].sum += m.marks_obtained;
                    studentMap[m.student_id].count++;
                });

                const processed = Object.values(studentMap).map(s => ({
                    ...s,
                    average: (s.sum / s.count).toFixed(2)
                }));

                setMarksData(processed);

                // Compute overall stats
                const allAverages = processed.map(p => parseFloat(p.average));
                setStats({
                    average: (allAverages.reduce((a, b) => a + b, 0) / (allAverages.length || 1)).toFixed(2),
                    highest: Math.max(...allAverages, 0),
                    lowest: Math.min(...allAverages, 0),
                    passing: processed.filter(p => p.average >= 40).length // Assuming 40 is pass
                });
            }
        } catch (err) {
            toast.error('Analysis failed');
        } finally {
            setLoading(false);
        }
    };

    const columns = [
        { header: 'Roll No', accessor: 'roll_no' },
        { header: 'Student Name', accessor: 'name' },
        { 
            header: 'CT-1', 
            render: (row) => row.tests['CT1'] ?? <span className="text-red-400">N/A</span> 
        },
        { 
            header: 'CT-2', 
            render: (row) => row.tests['CT2'] ?? <span className="text-red-400">N/A</span> 
        },
        { 
            header: 'Avg. Score', 
            accessor: 'average',
            render: (row) => (
                <div className="flex items-center gap-2">
                    <div className="flex-1 h-1.5 w-16 bg-slate-100 rounded-full overflow-hidden">
                        <div 
                            className={`h-full ${parseFloat(row.average) >= 75 ? 'bg-green-500' : parseFloat(row.average) >= 50 ? 'bg-amber-500' : 'bg-red-500'}`} 
                            style={{ width: `${Math.min(parseFloat(row.average), 100)}%` }}
                        />
                    </div>
                    <span className="font-bold text-slate-800">{row.average}</span>
                </div>
            )
        }
    ];

    return (
        <div className="space-y-6 animate-in fade-in duration-500 pb-20">
            <div className="flex items-center justify-between">
                <div>
                   <div className="flex items-center gap-2 text-indigo-600 mb-1">
                     <BarChart3 className="h-4 w-4" />
                     <span className="text-[10px] font-extrabold uppercase tracking-[0.2em]">Data Analytics</span>
                   </div>
                   <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Performance Intelligence</h2>
                   <p className="text-sm text-slate-500 font-medium">Cross-reference assessment scores with attendance trends.</p>
                </div>
                <Button variant="outline" className="bg-white">
                    <Download className="h-4 w-4 mr-2" />
                    Export Analysis
                </Button>
            </div>

            <div className="bg-white p-2 border border-slate-200 rounded-2xl shadow-sm flex flex-wrap items-center gap-2">
                <div className="flex items-center gap-2 p-1.5 bg-slate-50 rounded-xl border border-slate-100 flex-1 min-w-[150px]">
                    <select 
                        className="bg-transparent border-none text-sm font-bold text-slate-700 focus:ring-0 cursor-pointer w-full"
                        value={filter.branch}
                        onChange={(e) => setFilter({ ...filter, branch: e.target.value })}
                    >
                        {branches.map(b => <option key={b.id} value={b.name}>{b.name.toUpperCase()}</option>)}
                    </select>
                </div>
                <div className="flex items-center gap-2 p-1.5 bg-slate-50 rounded-xl border border-slate-100 w-32">
                    <select 
                        className="bg-transparent border-none text-sm font-bold text-slate-700 focus:ring-0 cursor-pointer w-full"
                        value={filter.sem}
                        onChange={(e) => setFilter({ ...filter, sem: e.target.value })}
                    >
                        {[1, 2, 3, 4, 5, 6, 7, 8].map(s => <option key={s} value={s.toString()}>SEM {s}</option>)}
                    </select>
                </div>
                <div className="flex items-center gap-2 p-1.5 bg-slate-50 rounded-xl border border-slate-100 flex-2 min-w-[200px]">
                    <select 
