import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import { Button } from '../../components/ui/Button';
import { Modal } from '../../components/ui/Modal';
import { Input } from '../../components/ui/Input';
import { Badge } from '../../components/ui/Badge';
import { Table } from '../../components/ui/Table';
import { ConfirmModal } from '../../components/ui/ConfirmModal';
import { toast } from '../../components/ui/Toast';
import { Bell, Pin } from 'lucide-react';

const TYPE_COLORS = {
  assignment: 'warning',
  lab: 'blue',
  library: 'purple',
  general: 'default',
};

export const Notices = () => {
  const { user, role } = useAuth();
  const [notices, setNotices] = useState([]);
  const [subjects, setSubjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [form, setForm] = useState({
    title: '', body: '', type: 'general', subject_id: '', branch: '', sem: '', due_date: '',
  });

  const canPost = role === 'admin' || role === 'hod' || role === 'teacher';

  useEffect(() => {
    fetchNotices();
    if (canPost) fetchSubjects();
  }, []);

  async function fetchNotices() {
    setLoading(true);
    const { data, error } = await supabase
      .from('notices')
      .select('*, users(name), subjects(code)')
      .eq('is_active', true)
      .order('is_pinned', { ascending: false })
      .order('created_at', { ascending: false });
    if (error) toast.error('Failed to load notices');
    else setNotices(data || []);
    setLoading(false);
  }

  async function fetchSubjects() {
    const { data } = await supabase.from('subjects').select('id, code, name');
    if (data) setSubjects(data);
  }

  const handlePost = async (e) => {
    e.preventDefault();
    const payload = {
      ...form,
      posted_by: user.id,
      subject_id: form.subject_id || null,
      sem: form.sem ? parseInt(form.sem) : null,
      due_date: form.due_date || null,
    };
    const { error } = await supabase.from('notices').insert([payload]);
    if (error) toast.error(error.message);
    else {
      toast.success('Notice posted');
      setIsModalOpen(false);
      setForm({ title: '', body: '', type: 'general', subject_id: '', branch: '', sem: '', due_date: '' });
      fetchNotices();
    }
  };

  const togglePin = async (id, pinned) => {
    await supabase.from('notices').update({ is_pinned: !pinned }).eq('id', id);
    fetchNotices();
  };

  const handleDelete = async () => {
    await supabase.from('notices').update({ is_active: false }).eq('id', deleteTarget);
    toast.success('Notice removed');
    setDeleteTarget(null);
    fetchNotices();
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-xl font-semibold text-slate-800">Notice Board</h2>
          <p className="text-sm text-slate-500">Announcements for assignments, labs, and general notices.</p>
        </div>
        {canPost && <Button onClick={() => setIsModalOpen(true)}>Post Notice</Button>}
      </div>

      {loading ? (
        <p className="text-slate-500 text-sm">Loading...</p>
      ) : notices.length === 0 ? (
        <div className="text-center py-16 text-slate-400">
          <Bell className="w-10 h-10 mx-auto mb-3 opacity-40" />
          <p>No notices yet.</p>
        </div>
      ) : (
        <div className="space-y-3">
          {notices.map((n) => (
            <div
              key={n.id}
              className={`bg-white border rounded-lg p-4 shadow-sm ${n.is_pinned ? 'border-indigo-300 bg-indigo-50/30' : 'border-slate-200'}`}
            >
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-2 flex-wrap">
                  {n.is_pinned && <Pin className="w-4 h-4 text-indigo-500" />}
                  <Badge variant={TYPE_COLORS[n.type]}>{n.type}</Badge>
                  {n.subjects && <Badge variant="default">{n.subjects.code}</Badge>}
                  {n.due_date && (
                    <span className="text-xs font-semibold text-red-600">
                      Due: {new Date(n.due_date).toLocaleDateString('en-IN')}
                    </span>
                  )}
                </div>
                {canPost && (
                  <div className="flex gap-2 shrink-0">
                    <Button variant="ghost" size="sm" onClick={() => togglePin(n.id, n.is_pinned)}>
                      {n.is_pinned ? 'Unpin' : 'Pin'}
                    </Button>
                    <Button variant="ghost" size="sm" onClick={() => setDeleteTarget(n.id)}>
                      Remove
                    </Button>
                  </div>
                )}
              </div>
              <h3 className="mt-2 font-semibold text-slate-800">{n.title}</h3>
              {n.body && <p className="mt-1 text-sm text-slate-600">{n.body}</p>}
              <div className="mt-2 text-xs text-slate-400">
                Posted by {n.users?.name || 'System'} •{' '}
                {new Date(n.created_at).toLocaleDateString('en-IN')}
                {n.branch && ` • Branch: ${n.branch}`}
                {n.sem && ` • Sem: ${n.sem}`}
              </div>
            </div>
          ))}
        </div>
      )}

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Post New Notice">
        <form onSubmit={handlePost} className="space-y-4">
          <Input label="Title" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} required />
          <div className="flex flex-col space-y-1">
            <label className="text-sm font-medium text-slate-700">Body</label>
            <textarea
              className="h-24 rounded border border-slate-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600 resize-none"
              value={form.body}
              onChange={(e) => setForm({ ...form, body: e.target.value })}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div className="flex flex-col space-y-1">
              <label className="text-sm font-medium text-slate-700">Type</label>
              <select
                className="h-10 rounded border border-slate-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600"
                value={form.type}
                onChange={(e) => setForm({ ...form, type: e.target.value })}
              >
                <option value="general">General</option>
                <option value="assignment">Assignment</option>
                <option value="lab">Lab</option>
                <option value="library">Library</option>
              </select>
            </div>
            <div className="flex flex-col space-y-1">
              <label className="text-sm font-medium text-slate-700">Subject (optional)</label>
              <select
                className="h-10 rounded border border-slate-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600"
                value={form.subject_id}
                onChange={(e) => setForm({ ...form, subject_id: e.target.value })}
              >
                <option value="">— None —</option>
                {subjects.map((s) => (
                  <option key={s.id} value={s.id}>{s.code} – {s.name}</option>
                ))}
              </select>
            </div>
            <Input label="Branch (optional)" placeholder="e.g. CS" value={form.branch} onChange={(e) => setForm({ ...form, branch: e.target.value })} />
            <Input label="Semester (optional)" type="number" min="1" max="8" value={form.sem} onChange={(e) => setForm({ ...form, sem: e.target.value })} />
          </div>
          <Input label="Due Date (optional)" type="datetime-local" value={form.due_date} onChange={(e) => setForm({ ...form, due_date: e.target.value })} />
          <div className="flex justify-end gap-2 pt-2">
            <Button variant="ghost" type="button" onClick={() => setIsModalOpen(false)}>Cancel</Button>
            <Button type="submit">Post</Button>
          </div>
        </form>
      </Modal>

      <ConfirmModal
        isOpen={!!deleteTarget}
        onClose={() => setDeleteTarget(null)}
        onConfirm={handleDelete}
        title="Remove Notice"
        message="Are you sure you want to remove this notice? It will no longer be visible."
      />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import { StatCard } from '../../components/ui/StatCard';
import { Badge } from '../../components/ui/Badge';
import { Table } from '../../components/ui/Table';
import { rawPercent, finalPercent, colorForPercent } from '../../utils/attendanceCalc';
import { toast } from '../../components/ui/Toast';
import { 
  TrendingUp, TrendingDown, Clock, 
  Target, GraduationCap, ChevronRight, 
  ArrowLeft, Calendar, Info 
} from 'lucide-react';

export const StudentAttendance = () => {
    const { user } = useAuth();
    const [student, setStudent] = useState(null);
    const [subjectData, setSubjectData] = useState([]);
    const [selectedSubject, setSelectedSubject] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (user) fetchData();
    }, [user]);

    const fetchData = async () => {
        setLoading(true);
        try {
            const { data: stu } = await supabase.from('students').select('id, roll_no, branch, sem').eq('user_id', user.id).single();
            if (!stu) return;
            setStudent(stu);

            const [subjects, lectures, attendance, condonation] = await Promise.all([
                supabase.from('subjects').select('id, code, name').eq('branch', stu.branch).eq('sem', stu.sem),
                supabase.from('lectures').select('id, subject_id, date, lecture_no').eq('sem', stu.sem).eq('is_skipped', false),
                supabase.from('attendance').select('lecture_id, status, remarks').eq('student_id', stu.id),
                supabase.from('attendance_condonation').select('subject_id, lectures_condoned').eq('student_id', stu.id).eq('status', 'approved')
            ]);

            const summary = (subjects.data || []).map(sub => {
                const subLectures = (lectures.data || []).filter(l => l.subject_id === sub.id);
                const subAtt = (attendance.data || []).filter(a => subLectures.some(l => l.id === a.lecture_id));
                const present = subAtt.filter(a => a.status === 'present').length;
                const total = subLectures.length;
                const condoned = (condonation.data || []).filter(c => c.subject_id === sub.id).reduce((acc, c) => acc + (c.lectures_condoned || 0), 0);

                const raw = rawPercent(present, total);
                const final = finalPercent(present, condoned, total);

                // Days until 75% logic
                let daysTo75 = 0;
                if (final < 75) {
                    // (present + x) / (total + x) >= 0.75
                    // present + x >= 0.75 * total + 0.75 * x
                    // 0.25 * x >= 0.75 * total - present
                    daysTo75 = Math.ceil((0.75 * total - present) / 0.25);
                    if (daysTo75 < 0) daysTo75 = 0;
                }

                return {
                    ...sub,
                    present, total, condoned, raw, final, daysTo75,
                    lectures: subLectures.map(l => ({
                        ...l,
                        status: subAtt.find(a => a.lecture_id === l.id)?.status || 'absent',
                        remarks: subAtt.find(a => a.lecture_id === l.id)?.remarks
                    })).sort((a,b) => new Date(b.date) - new Date(a.date))
                };
            });
            setSubjectData(summary);
        } catch (err) {
            toast.error('Failed to load attendance trend');
        } finally {
            setLoading(false);
        }
    };

    if (loading) return (
        <div className="flex items-center justify-center h-64">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
        </div>
    );

    if (selectedSubject) {
        return (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-500 pb-20">
                <Button variant="ghost" onClick={() => setSelectedSubject(null)} className="pl-0 text-slate-500 hover:text-indigo-600">
                    <ArrowLeft className="h-4 w-4 mr-2" />
                    Back to Subjects
                </Button>

                <div className="flex items-end justify-between">
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <Badge variant="indigo">{selectedSubject.code}</Badge>
                            <span className="text-xs text-slate-400 font-bold uppercase tracking-widest text-[10px]">Lecture History</span>
                        </div>
                        <h2 className="text-2xl font-bold text-slate-900">{selectedSubject.name}</h2>
                    </div>
                    <div className="flex flex-col items-end">
                        <span className={`text-3xl font-black ${colorForPercent(selectedSubject.final)}`}>{selectedSubject.final}%</span>
                        <span className="text-[10px] font-bold text-slate-400 uppercase">Current Performance</span>
                    </div>
                </div>

                <div className="bg-white rounded-3xl border border-slate-200 shadow-xl shadow-slate-200/50 overflow-hidden">
                    <Table 
                        columns={[
                            { 
                                header: 'Session Date', 
                                render: (row) => (
                                    <div className="flex flex-col">
                                        <span className="font-bold text-slate-700 text-xs">
                                            {new Date(row.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}
                                        </span>
                                        <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                                            {new Date(row.date).toLocaleDateString('en-IN', { weekday: 'long' })}
                                        </span>
                                    </div>
                                )
                            },
                            { 
                                header: 'Slot', 
                                render: (row) => <Badge variant="slate" className="font-mono">Lec #{row.lecture_no}</Badge> 
                            },
                            { 
                                header: 'Record', 
                                render: (row) => (
                                    <Badge variant={row.status === 'present' ? 'success' : 'danger'} className="px-3">
                                        {row.status.toUpperCase()}
                                    </Badge>
                                )
                            },
                            { 
                                header: 'Remarks', 
                                render: (row) => <span className="text-xs text-slate-500 italic">{row.remarks || '—'}</span> 
                            }
                        ]}
