import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Modal } from '../../components/ui/Modal';
import { Badge } from '../../components/ui/Badge';
import { toast } from '../../components/ui/Toast';

export const BorrowLecture = () => {
  const { user } = useAuth();
  const [logs, setLogs] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [timetableSlots, setTimetableSlots] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [form, setForm] = useState({ timetable_id: '', date: '', note: '' });

  useEffect(() => {
    fetchAll();
    supabase.from('users').select('id, name, college_id').eq('role', 'teacher').neq('id', user.id)
      .then(({ data }) => setTeachers(data || []));
    supabase.from('subject_assignments').select('subject_id, subjects(code, name, sem, branch)').eq('teacher_id', user.id)
      .then(async ({ data }) => {
        setAssignments(data || []);
        if (!data?.length) return;
        const subjectIds = data.map(a => a.subject_id);
        const { data: slots } = await supabase.from('timetable').select('id, day_of_week, lecture_no, branch, sem, subjects(code)').in('subject_id', subjectIds);
        setTimetableSlots(slots || []);
      });
  }, [user]);

  async function fetchAll() {
    setLoading(true);
    const { data } = await supabase.from('substitute_log')
      .select('*, original:users!substitute_log_original_teacher_id_fkey(name), substitute:users!substitute_log_substitute_teacher_id_fkey(name), timetable(day_of_week, lecture_no, branch, sem, subjects(code))')
      .or(`original_teacher_id.eq.${user.id},substitute_teacher_id.eq.${user.id}`)
      .order('created_at', { ascending: false });
    setLogs(data || []);
    setLoading(false);
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    const { error } = await supabase.from('substitute_log').insert([{
      timetable_id: form.timetable_id,
      date: form.date,
      original_teacher_id: user.id,
      substitute_teacher_id: form.substitute_teacher_id,
      note: form.note,
      status: 'pending',
    }]);
    if (error) toast.error(error.message);
    else { toast.success('Borrow request sent'); setIsModalOpen(false); setForm({ timetable_id: '', date: '', note: '' }); fetchAll(); }
  };

  const handleAccept = async (id) => {
    const { error } = await supabase.from('substitute_log').update({ status: 'accepted', accepted_by: user.id }).eq('id', id);
    if (error) toast.error(error.message);
    else { toast.success('Accepted'); fetchAll(); }
  };

  const handleReject = async (id) => {
    const { error } = await supabase.from('substitute_log').update({ status: 'rejected' }).eq('id', id);
    if (error) toast.error(error.message);
    else { toast.success('Rejected'); fetchAll(); }
  };

  const statusVariant = { pending: 'warning', accepted: 'success', rejected: 'danger' };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-xl font-semibold text-slate-800">Borrow Lecture</h2>
          <p className="text-sm text-slate-500">Request another teacher to cover your lecture slot, or accept incoming requests.</p>
        </div>
        <Button onClick={() => setIsModalOpen(true)}>New Borrow Request</Button>
      </div>

      {loading ? <p className="text-sm text-slate-500">Loading...</p> : (
        <div className="space-y-3">
          {logs.length === 0 && <p className="text-sm text-slate-400">No borrow requests yet.</p>}
          {logs.map(l => {
            const isIncoming = l.substitute_teacher_id === user.id;
            return (
              <div key={l.id} className="bg-white border border-slate-200 rounded-lg p-4 flex items-start justify-between gap-4">
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <Badge variant={statusVariant[l.status]}>{l.status}</Badge>
                    <Badge variant={isIncoming ? 'indigo' : 'default'}>{isIncoming ? 'Incoming' : 'Outgoing'}</Badge>
                  </div>
                  <p className="font-semibold text-slate-800">
                    {l.timetable?.subjects?.code} — {l.timetable?.day_of_week} Lec {l.timetable?.lecture_no}
                    <span className="text-xs text-slate-500 ml-2">({l.timetable?.branch}, Sem {l.timetable?.sem})</span>
                  </p>
                  <p className="text-sm text-slate-600">Date: {new Date(l.date).toLocaleDateString('en-IN')}</p>
                  <p className="text-sm text-slate-500">
                    {isIncoming ? `From: ${l.original?.name}` : `Substitute: ${l.substitute?.name}`}
                  </p>
                  {l.note && <p className="text-xs text-slate-400">Note: {l.note}</p>}
                </div>
                {isIncoming && l.status === 'pending' && (
                  <div className="flex flex-col gap-2 shrink-0">
                    <Button size="sm" onClick={() => handleAccept(l.id)}>Accept</Button>
                    <Button size="sm" variant="danger" onClick={() => handleReject(l.id)}>Decline</Button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="New Borrow Request">
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="flex flex-col space-y-1">
            <label className="text-sm font-medium text-slate-700">Date</label>
            <div className="flex gap-2">
              <Input type="date" className="flex-1" value={form.date} onChange={e => {
                setForm({ ...form, date: e.target.value, timetable_id: '' });
              }} required />
              <Button type="button" variant="secondary" onClick={() => {
                const today = new Date().toISOString().split('T')[0];
                setForm({ ...form, date: today, timetable_id: '' });
              }}>Today</Button>
              <Button type="button" variant="secondary" onClick={() => {
                const tomorrow = new Date();
                tomorrow.setDate(tomorrow.getDate() + 1);
                setForm({ ...form, date: tomorrow.toISOString().split('T')[0], timetable_id: '' });
              }}>Tomorrow</Button>
            </div>
          </div>
          <div className="flex flex-col space-y-1">
            <label className="text-sm font-medium text-slate-700">My Lecture Slot</label>
            <select className="h-10 rounded border border-slate-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600" value={form.timetable_id} onChange={e => setForm({ ...form, timetable_id: e.target.value })} required disabled={!form.date}>
              <option value="">Select slot...</option>
              {timetableSlots.filter(s => {
                if (!form.date) return true;
                const dayStr = new Date(form.date).toLocaleDateString('en-US', { weekday: 'long' }).toUpperCase();
                return s.day_of_week === dayStr;
              }).map(s => <option key={s.id} value={s.id}>{s.subjects?.code} — {s.day_of_week} Lec {s.lecture_no} ({s.branch}, Sem {s.sem})</option>)}
            </select>
          </div>
          <div className="flex flex-col space-y-1">
            <label className="text-sm font-medium text-slate-700">Substitute Teacher</label>
            <select className="h-10 rounded border border-slate-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600" value={form.substitute_teacher_id} onChange={e => setForm({ ...form, substitute_teacher_id: e.target.value })} required>
              <option value="">Select teacher...</option>
              {teachers.map(t => <option key={t.id} value={t.id}>{t.name} ({t.college_id})</option>)}
            </select>
          </div>
          <div className="flex flex-col space-y-1">
            <label className="text-sm font-medium text-slate-700">Note (optional)</label>
            <textarea className="h-16 rounded border border-slate-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600 resize-none" value={form.note} onChange={e => setForm({ ...form, note: e.target.value })} />
          </div>
          <div className="flex justify-end gap-2 pt-2">
            <Button variant="ghost" type="button" onClick={() => setIsModalOpen(false)}>Cancel</Button>
            <Button type="submit">Send Request</Button>
          </div>
        </form>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useAuth } from '../../hooks/useAuth';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Badge } from '../../components/ui/Badge';
import { Modal } from '../../components/ui/Modal';
import { Table } from '../../components/ui/Table';
import { toast } from '../../components/ui/Toast';
import { 
  FileCheck, ShieldAlert, Search, 
  Upload, CheckCircle, XCircle, 
  Clock, FileText 
} from 'lucide-react';

export const TeacherCondonation = () => {
    const { user } = useAuth();
    const [requests, setRequests] = useState([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [submitting, setSubmitting] = useState(false);

    // New Request Form
    const [form, setForm] = useState({ 
        student_roll: '', 
        subject_id: '', 
        lectures: '', 
        reason: '', 
        file: null 
    });
    const [assignments, setAssignments] = useState([]);
    const [resolvedStudent, setResolvedStudent] = useState(null);

    useEffect(() => {
        fetchRequests();
        fetchAssignments();
    }, []);

    const fetchRequests = async () => {
        setLoading(true);
        // Requests related to subjects this teacher handles
        const { data: myAssigned } = await supabase.from('subject_assignments').select('subject_id').eq('teacher_id', user.id);
        const subjectIds = myAssigned?.map(a => a.subject_id) || [];

        const { data } = await supabase.from('attendance_condonation')
            .select('*, student:students(roll_no, users(name)), subject:subjects(code, name)')
            .in('subject_id', subjectIds)
            .order('created_at', { ascending: false });

        if (data) setRequests(data);
        setLoading(false);
    };

    const fetchAssignments = async () => {
        const { data } = await supabase.from('subject_assignments')
            .select('subject_id, subjects(id, code, name)')
            .eq('teacher_id', user.id);
        if (data) setAssignments(data);
    };

    const resolveStudent = async () => {
        if (!form.student_roll) return;
        const { data } = await supabase.from('students')
            .select('id, users(name)')
            .eq('roll_no', form.student_roll.trim().toUpperCase())
            .single();
        if (data) setResolvedStudent(data);
        else {
            setResolvedStudent(null);
            toast.error('Student not found');
        }
    };

    const handleAction = async (id, status) => {
        const { error } = await supabase.from('attendance_condonation')
            .update({ status: status === 'approve' ? 'teacher_review' : 'rejected' })
            .eq('id', id);
        if (error) toast.error(error.message);
        else {
            toast.success(status === 'approve' ? 'Verification sent to HOD' : 'Request rejected');
            fetchRequests();
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!resolvedStudent || !form.subject_id || !form.lectures) return;

        setSubmitting(true);
        try {
            let docUrl = null;
            if (form.file) {
                const fileName = `${Date.now()}-${form.file.name}`;
                const { data: uploadData, error: uploadError } = await supabase.storage
                    .from('condonation_docs')
                    .upload(fileName, form.file);
                if (uploadError) throw uploadError;
                const { data: { publicUrl } } = supabase.storage.from('condonation_docs').getPublicUrl(fileName);
                docUrl = publicUrl;
            }

            const { error } = await supabase.from('attendance_condonation').insert({
                student_id: resolvedStudent.id,
                subject_id: form.subject_id,
                lectures_condoned: parseInt(form.lectures),
                reason: form.reason,
                document_url: docUrl,
                status: 'teacher_review',
                requested_by: user.id
            });

            if (error) throw error;
            toast.success('Condonation initiated and sent to HOD');
            setIsModalOpen(false);
            setForm({ student_roll: '', subject_id: '', lectures: '', reason: '', file: null });
            fetchRequests();
        } catch (err) {
            toast.error(err.message);
        } finally {
            setSubmitting(false);
        }
    };

    const columns = [
        { 
            header: 'Student', 
            render: (row) => (
                <div className="flex flex-col">
                    <span className="font-bold text-slate-800">{row.student?.users?.name}</span>
                    <span className="text-[10px] text-slate-400 font-bold uppercase">{row.student?.roll_no}</span>
                </div>
            )
        },
        { 
            header: 'Subject', 
            render: (row) => <Badge variant="slate">{row.subject?.code}</Badge> 
        },
        { header: 'Lectures', accessor: 'lectures_condoned' },
        { 
            header: 'Status', 
            render: (row) => (
                <Badge variant={row.status === 'approved' ? 'success' : row.status === 'rejected' ? 'danger' : 'warning'}>
                    {row.status.toUpperCase().replace('_', ' ')}
                </Badge>
            )
        },
        {
            header: 'Actions',
            render: (row) => (
                <div className="flex items-center gap-2">
                    {row.status === 'pending' && (
                        <>
                            <Button size="sm" onClick={() => handleAction(row.id, 'approve')} className="bg-green-600 hover:bg-green-700 h-8 px-2">
                                <CheckCircle className="h-4 w-4" />
                            </Button>
                            <Button size="sm" variant="danger" onClick={() => handleAction(row.id, 'reject')} className="h-8 px-2">
                                <XCircle className="h-4 w-4" />
                            </Button>
                        </>
                    )}
                    {row.document_url && (
                        <Button variant="ghost" size="sm" onClick={() => window.open(row.document_url, '_blank')} className="h-8 px-2 text-indigo-600">
                            <FileText className="h-4 w-4" />
                        </Button>
                    )}
                </div>
            )
        }
    ];

    return (
        <div className="space-y-6 animate-in fade-in duration-500 pb-20">
            <div className="flex items-center justify-between">
                <div>
                  <div className="flex items-center gap-2 text-indigo-600 mb-1">
                    <ShieldAlert className="h-4 w-4" />
                    <span className="text-[10px] font-extrabold uppercase tracking-[0.2em]">Academic Exceptions</span>
                  </div>
                  <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Condonation Review</h2>
                  <p className="text-sm text-slate-500 font-medium">Verify absence justifications and medical exemptions.</p>
                </div>
                <Button onClick={() => setIsModalOpen(true)}>
                    <PlusIcon className="h-4 w-4 mr-2" />
                    Initiate Request
                </Button>
            </div>

            <div className="bg-white rounded-3xl border border-slate-200 shadow-xl shadow-slate-200/50 overflow-hidden">
                <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
                    <h3 className="font-bold text-slate-900 flex items-center gap-2">
                        <FileCheck className="h-4 w-4 text-indigo-600" />
                        Active Requests
                    </h3>
                    <div className="flex items-center gap-2">
                        <Badge variant="warning">{requests.filter(r => r.status === 'pending').length} Action Required</Badge>
                    </div>
                </div>
                <Table columns={columns} data={requests} loading={loading} emptyMessage="No condonation requests found." />
            </div>

            <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Initiate Condonation">
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="space-y-4">
                        <div className="flex items-end gap-2">
                            <div className="flex-1">
                                <Input 
                                    label="Student Roll No" 
                                    placeholder="e.g. 2024CS101" 
                                    value={form.student_roll}
                                    onChange={e => setForm({...form, student_roll: e.target.value})}
                                    required
                                />
                            </div>
                            <Button type="button" variant="outline" onClick={resolveStudent} className="h-10">
                                <Search className="h-4 w-4" />
                            </Button>
                        </div>
                        {resolvedStudent && (
                            <div className="p-3 bg-green-50 border border-green-100 rounded-xl flex items-center gap-3">
                                <CheckCircle className="h-4 w-4 text-green-500" />
                                <span className="text-sm font-bold text-green-700">Student: {resolvedStudent.users?.name}</span>
                            </div>
                        )}

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-1.5">
                                <label className="text-sm font-medium">Subject Context</label>
                                <select 
                                    className="w-full text-sm font-medium p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-600"
                                    value={form.subject_id}
                                    onChange={e => setForm({...form, subject_id: e.target.value})}
                                    required
                                >
                                    <option value="">Select subject...</option>
                                    {assignments.map(a => <option key={a.subject_id} value={a.subject_id}>{a.subjects?.code} - {a.subjects?.name}</option>)}
                                </select>
                            </div>
                            <Input 
                                label="Lectures to Condone" 
                                type="number" 
                                placeholder="e.g. 5"
                                value={form.lectures}
                                onChange={e => setForm({...form, lectures: e.target.value})}
                                required
                            />
                        </div>

                        <div className="space-y-1.5">
                            <label className="text-sm font-medium">Reason / Remarks</label>
                            <textarea 
